/* map q06 (193 mục) — engine-API đợt 608-634 Ch.634 */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q06"]=window.__LIBQ["tien-nghich"]["q06"]||{};window.__LIBQ["tien-nghich"]["q06"]["map"]={"updatedAt":"2026-06-24","count":193,"nodes":[{"id":"tien-canh-tang-bay-pham-linh-cac","name":"Tiên cảnh (tầng bảy Phẩm Linh Các)","cn":"","capDo":"khac","parentId":"pham-linh-cac","blurb":"Thế giới truyền tống ở tầng thứ bảy Phẩm Linh Các, đầy hương hoa, nước chảy, mây bảy sắc và tiên hạc; có nhân ảnh khổng lồ canh giữ và phát tiên ngọc.","detail":"Cánh cửa ánh sáng tại tầng thứ bảy Phẩm Linh Các có tác dụng truyền tống, đưa đệ tử vào một thế giới như tiên cảnh tràn ngập hương hoa, nước chảy, mây bảy sắc và tiên hạc. Một nhân ảnh khổng lồ kết từ mây bảy sắc canh giữ nơi này, tỏa tiên lực mạnh, xác nhận thân phận đệ tử và phát tiên ngọc theo yêu cầu.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0458"]},{"id":"toa-lau-truc-chap-phap-thien-van-tong","name":"Tòa lầu trúc (chấp pháp trưởng lão)","cn":"","capDo":"khac","parentId":"thien-van-tinh","blurb":"Tòa lầu trúc trong Thiên Vận Tông, nơi ba chấp pháp trưởng lão ngồi bàn luận về Vương Lâm.","detail":"Một tòa lầu trúc trong tông sơn Thiên Vận Tông, nơi ba chấp pháp trưởng lão ngồi bàn luận về tốc độ, sức mạnh và cấm ngôn chiến đấu phong phú của Vương Lâm, đồng thời nhắc lệnh của Thủy tổ và sự khốc liệt của cạnh tranh nội bộ.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0458"]},{"id":"thach-lam-khon-dia","name":"Thạch lâm (khốn địa)","cn":"","capDo":"khac","parentId":null,"blurb":"Vùng thạch lâm hoang vu ngoài Thiên Vận Tông, nơi Vương Lâm bị vây khốn bế quan.","detail":"Một thạch lâm cực lớn nằm ngoài Thiên Vận Tông hơn mười ngàn dặm, chi chít cự thạch sắc bén như kiếm đâm lên trời, tỏa sát khí kỳ lạ kết thành ngọn lửa sát khí. Cực kỳ hoang vu, tu sĩ lui tới phần lớn là tán tu và không ai dám đến gần. Bên trong được bố trí trận pháp khốn địa với màn sáng bạc bao phủ mười dặm; đây là nơi Vương Lâm bị tứ sư tỷ na di tới và vây bế quan ba năm.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0459"]},{"id":"nam-tieu-tinh-cau-thien-van","name":"Năm tiểu tinh cầu (Thiên Vận Tinh)","capDo":"khac","parentId":"thien-van-tinh","blurb":"Năm tiểu tinh cầu phụ cận Thiên Vận Tinh, nơi tu sĩ kéo về chủ tinh chúc thọ.","detail":"Năm tiểu tinh cầu vây quanh Thiên Vận Tinh, là địa bàn phụ thuộc của các tu sĩ và lão quái trong vùng. Khi đại thọ ngàn năm của Thiên Vận Tử mở ra, tu sĩ từ năm tiểu tinh cầu này kéo về chủ tinh dự yến.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0460"]},{"id":"thien-nguc-thien-van-tong","name":"Thiên ngục (Thiên Vận Tông)","capDo":"khac","parentId":"thien-van-tinh","blurb":"Nơi giam giữ và bế quan trừng phạt của Thiên Vận Tông.","detail":"Địa điểm trong phạm vi Thiên Vận Tông dùng để giam giữ và bế quan trừng phạt. Lão ngũ trong Thiên Vận Thất tử bị sư tôn đưa vào thiên ngục bế quan trăm năm.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0460"]},{"id":"thach-lam-cach-thien-van-tong","name":"Thạch lâm (cách Thiên Vận Tông hơn mười ngàn dặm)","capDo":"khac","parentId":"thien-van-tinh","blurb":"Rừng đá cách Thiên Vận Tông hơn mười ngàn dặm, bị phá nát trong phạm vi mười dặm khi nam tử tóc dài đột phá.","detail":"Một rừng đá rộng lớn cách Thiên Vận Tông hơn mười ngàn dặm. Nam tử tóc dài (khả năng cao là Vương Lâm) ngồi khoanh chân trên một tảng đá tại đây, khi mở mắt đột phá liền nhấn tay khiến thạch lâm trong mười dặm nứt vỡ tan thành bụi, chỉ tảng đá hắn ngồi còn nguyên.","theLucLienQuan":[],"nguon":["@c0460"]},{"id":"son-mon-thien-van-tong","name":"Sơn môn Thiên Vận Tông","cn":"","capDo":"khac","parentId":"thien-van-tinh","blurb":"Sơn môn của Thiên Vận Tông trên Thiên Vận Tinh, cách thạch lâm khoảng ba mươi vạn dặm về hướng tây.","detail":"Nơi mở thọ yến ngàn năm cho sư tôn Thiên Vận Tử. Khu vực Tử tông được mây lớn ngưng tụ cứng như mặt đất bao phủ; bàn tiệc bày tiên quả sơn tửu náo nhiệt, là điểm Vương Lâm lao tới để báo thù.","theLucLienQuan":["Thiên Vận Tông","Tử tông"],"nguon":["@c0461"]},{"id":"dinh-nui-na-di-thien-van-tinh","name":"Đỉnh núi cách mười vạn dặm (Thiên Vận Tinh)","cn":"","capDo":"khac","parentId":"thien-van-tinh","blurb":"Đỉnh núi cách Tử Lâm Các mười vạn dặm, nơi Vương Lâm dịch chuyển tới khi thử Đại Na Di.","detail":"Đỉnh núi nằm trên Thiên Vận Tinh, cách Tử Lâm Các mười vạn dặm. Khi Vương Lâm thử thành công cấm pháp Đại Na Di lần đầu, thân biến mất rồi xuất hiện tại đây, gây nổ tung bụi đất; đây cũng là dấu hiệu xác nhận hắn đã ở đúng Thiên Vận Tinh chứ không phải Chu Tước Tinh.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0464"]},{"id":"thung-lung-heo-lanh-cuu-chuyen","name":"Thung lũng hẻo lánh (Thiên Vận Tinh)","cn":"","capDo":"khac","parentId":"thien-van-tinh","blurb":"Thung lũng hẻo lánh nơi Vương Lâm ngồi nghiền ngẫm và tu Cửu Chuyển Luyện Tiên Quyết.","detail":"Sau khi bay khỏi đỉnh núi dịch chuyển, Vương Lâm tìm tới một thung lũng hẻo lánh trên Thiên Vận Tinh để xem cấm pháp thứ hai và lần lượt tu thành nhất chuyển, nhị chuyển, tam chuyển của Cửu Chuyển Luyện Tiên Quyết, ngưng kim tiên lực ở tay trái.","theLucLienQuan":[],"nguon":["@c0464"]},{"id":"tu-vi-cac-thien-van","name":"Tử Vi Các","cn":"","capDo":"khac","parentId":"son-mon-thien-van-tong","blurb":"Kiến trúc nơi Bạch Vi trở về sau yến hội Tử hệ.","detail":"Nơi ở của Bạch Vi trong sơn môn Thiên Vận Tông. Sau yến hội ngày cuối, Bạch Vi rời yến hội về Tử Vi Các; trên đường đi lộ vẻ ác độc, lẩm bẩm trách sư tôn cấy yêu linh vào đại sư huynh.","theLucLienQuan":["Tử Tông"],"nguon":["@c0464"]},{"id":"tien-gioi","name":"Tiên giới","capDo":"gioi-dien","parentId":null,"blurb":"Cõi Tiên được nhắc đã bị hủy diệt; Dẫn Tiên thuật vẫn tiếp dẫn người lên Tiên giới, dấy lên nghi vấn nơi chốn.","detail":"Tiên giới được nhắc tới như cõi đã bị hủy diệt, phá toái. Khi Thiên Vận Tử thi triển Dẫn Tiên thuật tiếp dẫn người lên Tiên giới, đám tu sĩ kinh ngạc thắc mắc Tiên giới đã hủy diệt thì người bị đưa đi sẽ đến đâu, là Tiên giới phá toái hay một nơi chưa ai từng đặt chân.","theLucLienQuan":[],"nguon":["@c0468"]},{"id":"hac-mac-tinh","name":"Hắc Mặc Tinh","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu nơi Trần Đào cướp được Thất thải lưu ly quang từ ba con thượng phẩm hoang thú.","detail":"Một tinh cầu nơi Trần Đào trong thời gian rèn luyện ở tinh ngoại đã đoạt được đoá Thất thải lưu ly quang từ ba con thượng phẩm hoang thú, rồi mang về dâng cho Thiên Vận Tử.","theLucLienQuan":[],"nguon":["@c0470"]},{"id":"hoang-tuyen-coi","name":"Hoàng tuyền","cn":"","capDo":"khac","parentId":null,"blurb":"Cõi sống-chết được biểu thị qua tranh cuốn sơn thủy khi thi triển Hoàng tuyền chỉ; nơi Tư Đồ Nam từng cảm ngộ giữa sống chết.","detail":"Cõi sống-chết, được biểu thị qua một bức tranh cuốn sơn thủy hiện ra khi thi triển Hoàng tuyền chỉ. Người tu Hoàng tuyền thăng khiếu quyết thông qua sinh mệnh tiến nhập Hoàng tuyền, biến chuyển sống-chết mà cảm ngộ; Tư Đồ Nam năm xưa từng cảm ngộ giữa sống chết tại nơi này để tạo ra Hoàng tuyền chỉ.","theLucLienQuan":[],"nguon":["@c0471"]},{"id":"yeu-tinh","name":"Yêu Tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu nơi Trần Đào từng ở hơn năm trăm năm và rút Long cân từ xác một con yêu long.","detail":"Địa danh dạng tinh cầu nơi Trần Đào ở hơn năm trăm năm; tại đây hắn rút Long cân ra từ xác một con yêu long đã chết, luyện thành pháp bảo khốn trói.","theLucLienQuan":[],"nguon":["@c0471"]},{"id":"tong-tong-ba-ngon-nui-thien-van","name":"Tổng tông Thiên Vận (ba ngọn núi)","capDo":"khac","parentId":"thien-van-tinh","blurb":"Tổng tông Thiên Vận Tông đặt tại Thiên Vận Tinh, vùng thiên địa đẹp hơn tiên cảnh với ba ngọn núi cao chọc trời.","detail":"Tổng tông là một vùng thiên địa đẹp hơn tiên cảnh, có ba ngọn núi cao chọc trời tạo bức tranh sơn thủy đen trắng chấn thiên kinh địa. Ngọn giữa thật phủ bạch tuyết Cửu U chi hàn; hai ngọn hai bên đen tuyền với tuyết đen rơi xuống nhưng là giả do Chân huyễn pháp của Thiên Vận Tử dựng nên. Đây là nơi đệ tử chân chính tế bái Tổ linh và nhận Cấm pháp thần thông.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0472"]},{"id":"ngon-nui-trang-cuu-u","name":"Ngọn núi trắng Cửu U chi hàn","capDo":"khac","parentId":"tong-tong-ba-ngon-nui-thien-van","blurb":"Ngọn núi thật ở giữa Tổng tông, phủ bạch tuyết Cửu U chi hàn mười vạn năm không tan.","detail":"Ngọn núi giữa trong ba ngọn của Tổng tông, phủ bạch tuyết Cửu U chi hàn mười vạn năm không tan. Phàm nhân trong vòng nghìn trượng sẽ bị đông cứng thành thi thể băng; là nơi tuyệt vời để tu công pháp âm hàn. Đệ tử mới nhận phải leo ngọn này không dùng thuấn di, lên càng nhanh càng nhận được nhiều phần thưởng tốt.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0472"]},{"id":"toai-tien-chi-dia","name":"Toái Tiên chi địa","capDo":"khac","parentId":"ngon-nui-trang-cuu-u","blurb":"Một trăm bước cuối trước đỉnh ngọn núi trắng, hàn khí cực mạnh, là nơi khảo nghiệm Vấn Tâm và phúc phận.","detail":"Một trăm bước đầu khi leo ngọn núi trắng tương đối dễ, nhưng một trăm bước cuối trước đỉnh gọi là Toái Tiên chi địa, hàn khí cực dày xông từ mặt đất vào kinh mạch, phải dựa vào tâm cảnh và phúc phận mới vượt được. Đây là nơi khảo nghiệm Vấn Tâm: hàn khí thật không lạnh bằng cái lạnh trong tâm người tu. Có ghi nhận kỷ lục bước chân — Tôn Vân năm xưa đi hai mươi sáu bước với tu vi Anh Biến hậu kỳ; Vương Lâm với Anh Biến trung kỳ vượt hai mươi mốt bước rồi tiếp tục.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0472"]},{"id":"the-gioi-bay-mau","name":"Thế giới bảy màu","capDo":"khac","parentId":null,"blurb":"Cảnh giới vô biên vô tận mở ra trong tâm thần Thiên Vận Tử, chứa 3600 (thực ra 3601) Thiên Vận Tử tu luyện các Cấm pháp thần thông khác nhau.","detail":"Không gian mở ra từ ánh sáng bảy màu trên tay Thiên Vận Tử, nơi Vương Lâm bước vào để chọn thần thông theo cơ duyên. Có 3600 Thiên Vận Tử giống hệt nhau, mỗi người tu luyện/chiến đấu một loại Cấm pháp thần thông; trong đó ẩn một Thiên Vận Tử áo xám — ‘hơn một người’, là thực thể thứ 3601.","theLucLienQuan":[],"nguon":["@c0474"]},{"id":"dia-tinh","name":"Địa Tinh","cn":"","capDo":"tinh-cau","parentId":"thien-van-tinh","blurb":"Một trong năm tinh cầu phụ quay quanh Thiên Vận Tinh, màu vàng, hầu như toàn đất liền.","detail":"Địa Tinh là một trong năm tinh cầu phụ quay quanh Thiên Vận Tinh, màu vàng, nhiều quầng sáng, kích cỡ xấp xỉ Chu Tước Tinh, hầu như toàn đất liền ít đại dương. Trên Địa Tinh có Huyền Uyên Phái (Lục cấp tu chân quốc duy nhất) và Linh Nhạc quốc (Ngũ cấp tu chân quốc) cách nhau khoảng trăm vạn dặm.","theLucLienQuan":["Huyền Uyên Phái","Linh Nhạc quốc"],"nguon":["@c0476"]},{"id":"linh-nhac-quoc-map","name":"Linh Nhạc quốc","cn":"","capDo":"quoc-gia","parentId":"dia-tinh","blurb":"Ngũ cấp tu chân quốc nhỏ phía Tây Địa Tinh, nổi danh đặc sản Tý Linh vật.","detail":"Linh Nhạc quốc nằm cách Huyền Uyên Phái khoảng trăm vạn dặm về phía Tây trên Địa Tinh, là Ngũ cấp tu chân quốc nhỏ chỉ có bốn tông phái nhưng đặc sản Tý Linh vật nổi danh khắp Địa Tinh; là nơi Vương Lâm tới nhậm chức sứ giả.","theLucLienQuan":["Linh Nhạc quốc"],"nguon":["@c0476"]},{"id":"thap-choc-troi-linh-nhac","name":"Tháp chọc trời Linh Nhạc quốc","cn":"","capDo":"khac","parentId":"linh-nhac-quoc-map","blurb":"Toà tháp lớn ở trung tâm Linh Nhạc quốc, chỗ ở của các thế hệ sứ giả.","detail":"Một toà tháp chọc trời nằm ở trung tâm Linh Nhạc quốc, là chỗ ở của các thế hệ sứ giả được phái tới đây.","theLucLienQuan":["Linh Nhạc quốc"],"nguon":["@c0476"]},{"id":"ngu-linh-son","name":"Ngũ Linh Sơn","cn":"","capDo":"khac","parentId":"linh-nhac-quoc-map","blurb":"Ngọn núi nơi Thiên Thai lão nhân ngồi tu tại Linh Nhạc quốc, đỉnh núi có thái âm lực.","detail":"Ngũ Linh Sơn là chỗ ở của Thiên Thai lão nhân, cao thủ đệ nhất Linh Nhạc quốc. Trên đỉnh núi tích tụ thái âm lực để lão hấp thu thổ nạp; cuối chương 477 Vương Lâm tìm đến đây gặp lão.","theLucLienQuan":["Ngũ Linh Sơn","Linh Nhạc quốc"],"nguon":["@c0477"]},{"id":"dong-hai-thien-van-tinh","name":"Đông Hải","cn":"","capDo":"khac","parentId":"thien-van-tinh","blurb":"Nơi Thiên Vận Tử áo xám dặn Vương Lâm phải đến trong vòng ba tháng.","detail":"Địa điểm sư phụ dặn Vương Lâm phải đến trong ba tháng; tới cuối chương 477 chỉ còn hơn một tháng nên hắn quyết lên đường.","theLucLienQuan":[],"nguon":["@c0477"]},{"id":"dia-ma-bac-gioi","name":"Địa Ma Bắc Giới","capDo":"khac","parentId":"dia-tinh","blurb":"Hiểm địa phía sau tấm bia đá lớn khắc bốn chữ đỏ đầy sát khí ở Cực Bắc Địa Tinh, nơi Vương Lâm tu Sát Lục Tiên quyết.","detail":"Khu vực phía sau tấm bia đá lớn khắc bốn chữ đỏ đầy sát khí Địa Ma Bắc Giới, đặt ở Cực Bắc Địa Tinh. Quanh bia quái phong gào thét; phía sau là dãy núi liên miên vô tận, mặt đất phủ lá thối, âm hàn yên tĩnh. Vương Lâm chọn nơi đây làm chốn tu luyện Sát Lục Tiên quyết vì công pháp cần giết chóc mới lĩnh ngộ.","theLucLienQuan":[],"nguon":["@c0478"]},{"id":"tung-mang-son","name":"Tùng Mãng Sơn","capDo":"khac","parentId":"dia-tinh","blurb":"Vùng trăm vạn dặm ở Cực Bắc Địa Tinh tụ tập vô số yêu thú, nơi đệ tử các tông phái thí luyện.","detail":"Vùng rộng trăm vạn dặm ở Cực Bắc Địa Tinh, tụ tập vô số yêu thú, có cả Hoang thú thực lực tương đương Vấn Đỉnh. Là nơi đệ tử các tông phái thí luyện, nhưng ba mươi vạn dặm trung tâm là cấm địa.","theLucLienQuan":[],"nguon":["@c0478"]},{"id":"dia-ma-bac-gioi-c0479","name":"Địa Ma Bắc Giới","cn":"","capDo":"vuc","parentId":null,"blurb":"Khu vực phủ sương mù mỏng, chứa nhiều yêu thú, là nơi có Diệu Kim quả được yêu thú thủ hộ.","detail":"Địa Ma Bắc Giới là khu vực phủ một lớp sương mù mỏng, bên trong chứa nhiều yêu thú. Đây là nơi cất giấu Diệu Kim quả do yêu thú cường đại thủ hộ. Thiên Cầm bị ép dẫn đoàn Đại La Kiếm Tông vào đây; đoàn người dung nhập vào sương mù rồi mất bóng.","theLucLienQuan":["Đại La Kiếm Tông","Sư môn của Thiên Cầm"],"nguon":["@c0479"]},{"id":"son-coc-dieu-kim-qua","name":"Sơn cốc Diệu Kim quả","capDo":"khac","parentId":"dia-ma-bac-gioi","blurb":"Sơn cốc nơi giao nhau hai ngọn núi trong Địa Ma Bắc Giới, nơi mọc phiến Diệu Kim quả và ẩn ổ Cửu Lê trùng.","detail":"Sơn cốc nằm chỗ giao nhau của hai ngọn núi trong Địa Ma Bắc Giới, lá cây mục rữa mùi khó ngửi, ẩn kim mang. Sư môn vãn bối của Thiên Cầm phát hiện Diệu Kim quả tại đây hai tháng trước. Cuối thông đạo do Thạch Phương mở ra lộ một phiến hoa vàng không dưới mười đoá, bên dưới là đám quả nhỏ hình trứng màu vàng nhạt — Diệu Kim quả. Cách đó tầm một trượng, dưới lá khô và cỏ dại là một tảng lớn điểm đỏ rậm rạp: ổ Cửu Lê trùng làm mãnh thú thủ hộ.","theLucLienQuan":["Đại La Kiếm Tông"],"nguon":["@c0480"]},{"id":"dong-hai-yeu-linh-chi-mon","name":"Đông Hải Yêu Linh chi môn","cn":"","capDo":"khac","parentId":"dong-hai-thien-van-tinh","blurb":"Một trong ba đại cấm địa bên ngoài Thiên Vận tinh; mở mỗi năm ngàn năm, là nơi huyết tinh thí luyện cực hung hiểm.","detail":"Cấm địa quyền quản lý một vạn năm đổi một lần, hiện do Đại La Kiếm Tông quản. Bên trong có Cổ Yêu, cứ năm ngàn năm mở một lần; các tông phái phái đệ tử nổi bật vào bắt Cổ Yêu, nhưng mục đích chính là huyết tinh thí luyện. Người đi ra càng ít thì chỗ tốt càng nhiều; chỗ tốt chân chính là được Yêu Linh quán đính một lần khi ra ngoài. Đây cũng là nơi Kiếm Tôn phong ấn hơn 1/3 kiếm hồn cùng Chu Dật, và là mục tiêu chuyến đi của Vương Lâm.","theLucLienQuan":["Đại La Kiếm Tông","Thiên Vận Tông"],"nguon":["@c0485"]},{"id":"huyet-tinh","name":"Huyết Tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu bên ngoài Thiên Vận Tinh do Huyết Tổ Diêu Tinh Hải độc chiếm, khai hoang nạp huyết tu luyện ma công.","detail":"Huyết Tổ độc chiếm và cải tạo cả tinh cầu này thành nơi nạp huyết tu luyện ma công; hai người phụ nữ của lão (gồm con gái Diêu Tích Tuyết) quanh năm cư ngụ ở đây, không tiếp xúc người ngoài, không ai dám chọc.","theLucLienQuan":["Huyết Tổ Diêu Tinh Hải","Diêu Tích Tuyết"],"nguon":["@c0486"]},{"id":"nam-pho-tinh-thien-van","name":"Năm phó tinh ngoài Thiên Vận Tinh","cn":"","capDo":"tinh-cau","parentId":"thien-van-tinh","blurb":"Năm tinh cầu phụ có mặt đất bao quanh Thiên Vận Tinh; Huyền Uyên phái đặt một tòa truyền tống trận khổng lồ trên một trong số đó.","detail":"Một trong năm phó tinh là nơi Huyền Uyên phái dựng truyền tống trận pháp khổng lồ, do mấy trăm đệ tử phóng linh lực phối hợp tiên ngọc khởi động để đưa người tới Đông Hải Yêu Linh.","theLucLienQuan":["Huyền Uyên Phái"],"nguon":["@c0486"]},{"id":"the-gioi-dong-hai-yeu-linh","name":"Thế giới Đông Hải yêu linh","capDo":"gioi-nho","parentId":"dong-hai-yeu-linh-chi-mon","blurb":"Thế giới hỗn độn tự hình thành bên trong cánh cửa Đông Hải yêu linh.","detail":"Bên trong cánh cửa Đông Hải yêu linh là một thế giới hỗn độn tự hình thành, có trời đất biển giống thế giới phàm nhân, không giống nơi thí luyện trọng bảo. Thí luyện kéo dài năm trăm năm; người vừa vào bị một lực kỳ dị đẩy tản ra khắp nơi. Vương Lâm rơi xuống một vùng hoang nguyên.","theLucLienQuan":["Thiên Vận Tông","Đại La kiếm tông"],"nguon":["@c0491"]},{"id":"dai-la-tinh","name":"Đại La tinh","capDo":"tinh-cau","parentId":null,"blurb":"Đại tinh cầu Lăng Thiên Hậu đưa từ tinh không tới, nơi đặt Đại La kiếm tông.","detail":"Một đại tinh cầu Lăng Thiên Hậu đưa từ tinh không tới và đặt tên Đại La tinh, lớn hơn năm đại phó tinh gấp mấy lần, linh lực sung túc. Đây là nơi đặt Đại La kiếm tông; đông bộ là chỗ Lăng Thiên Hậu phá cương phong vào bế quan luyện hóa Tiên kiếm.","theLucLienQuan":["Đại La kiếm tông"],"nguon":["@c0491"]},{"id":"binh-nguyen-hoang-vu-dong-hai-yeu-linh","name":"Bình nguyên hoang vu","cn":"","capDo":"vuc","parentId":"the-gioi-dong-hai-yeu-linh","blurb":"Vùng đồng bằng rộng lớn yên tĩnh, không có sinh mạng, Vương Lâm bay qua mất mười ngày.","detail":"Bình nguyên hoang vu trong vùng Đông Hải yêu linh, khắp nơi yên tĩnh, không có sinh mạng nào ngoài Vương Lâm. Hắn quét thần thức không thấy gì kỳ dị, bay liền mười ngày mới ra tới rìa và phát hiện vùng núi non phía xa.","theLucLienQuan":[],"nguon":["@c0492"]},{"id":"vung-nui-non-trung-diep-dong-hai-yeu-linh","name":"Vùng núi non trùng điệp","cn":"","capDo":"vuc","parentId":"the-gioi-dong-hai-yeu-linh","blurb":"Khu rừng núi cây cối xanh biếc ngoài rìa bình nguyên hoang vu, có dã thú và người xích lõa sinh sống.","detail":"Vùng núi non trùng điệp cây cối xanh biếc nằm ngoài rìa bình nguyên hoang vu. Trong rừng có dã thú lớn không linh lực và những người nửa xích lõa ẩn thân săn bắt. Bên trong vùng có một sơn cốc được trận pháp thượng cổ bảo vệ.","theLucLienQuan":[],"nguon":["@c0492"]},{"id":"son-coc-tran-phap-thuong-co-dong-hai-yeu-linh","name":"Sơn cốc (trận pháp thượng cổ, Đông Hải yêu linh)","cn":"","capDo":"khac","parentId":"vung-nui-non-trung-diep-dong-hai-yeu-linh","blurb":"Sơn cốc được trận pháp thượng cổ bảo vệ, nơi cư ngụ của những người nửa xích lõa thân phủ chất lỏng xanh.","detail":"Sơn cốc trong vùng núi non Đông Hải yêu linh, bên ngoài có trận pháp ẩn giấu mọi khí tức sinh mạng do tu sĩ thượng cổ bố trí. Bên trong cư ngụ chủng người nửa xích lõa, thân phủ chất lỏng xanh biếc, cầm vũ khí u quang loang lổ, không có linh lực nhưng linh tính kinh người. Vương Lâm nhận xét nơi đây khác hẳn các nơi hắn từng tới tìm bảo vật.","theLucLienQuan":[],"nguon":["@c0492"]},{"id":"son-coc-bo-toc-au-duong-hoa","name":"Sơn cốc (cốc bộ tộc Âu Dương Hoa)","cn":"","capDo":"khac","parentId":null,"blurb":"Sơn cốc nơi bộ tộc thân trâu mình người sinh sống, được thượng cổ trận pháp bảo vệ.","detail":"Nơi cư trú của bộ tộc Âu Dương Hoa, được trận pháp thượng cổ bao bọc. Bên ngoài cốc là khu vực Vương Lâm bày trận phá cấm chế; nơi máu tế của tộc nhân rơi xuống dâng lên huyết vụ đỏ dày đặc.","theLucLienQuan":["Bộ tộc sơn cốc (bộ tộc Âu Dương Hoa)"],"nguon":["@c0493"]},{"id":"co-yeu-thanh","name":"Cổ yêu thành","cn":"","capDo":"thanh","parentId":null,"blurb":"Tòa thành trì rất lớn nằm ngoài ba ngàn dặm tính từ sơn cốc, nơi Âu Dương Hoa thuở nhỏ từng học tập.","detail":"Tòa thành lớn cách sơn cốc bộ tộc Âu Dương Hoa hơn ba ngàn dặm. Âu Dương Hoa thuở nhỏ từng học tập ở đó nên có tuổi thọ rất cao. Lão khẳng định thứ Vương Lâm cần tìm không có ở bộ tộc mình mà có thể tìm thấy tại Cổ yêu thành, định hướng mục tiêu hành trình tiếp theo của Vương Lâm.","theLucLienQuan":[],"nguon":["@c0493"]},{"id":"thien-yeu-quan-map","name":"Thiên Yêu quận","cn":"","capDo":"chau","parentId":"dong-hai-yeu-linh","blurb":"Một trong chín quận của thiên hạ nơi yêu linh; quận nơi sơn cốc của Vương Lâm tọa lạc, thuộc nơi man hoang ở rìa.","detail":"Thiên Yêu quận là một trong chín quận của thiên hạ nơi yêu linh, do yêu đế Tai Hư cùng bát đại yêu soái cai quản. Quận có thiên vạn yêu binh và hơn trăm thành trì, trong đó Cổ yêu th��nh là một trong những thành trì. Sơn cốc hình hồ lô của bộ lạc Âu Dương Hoa nằm ở vùng man hoang ở rìa của quận này.","theLucLienQuan":["Thiên Yêu quận","Bộ lạc sơn cốc (Âu Dương Hoa)"],"nguon":["@c0496"]},{"id":"dong-hai-yeu-linh","name":"Đông Hải yêu linh (nơi yêu linh)","cn":"","capDo":"gioi-nho","parentId":null,"blurb":"Vùng yêu linh rộng lớn có tổng cộng chín quận; mỗi đêm trăng tròn là đêm yêu linh đi săn mồi.","detail":"Đông Hải yêu linh, hay nơi yêu linh, là một vùng rộng lớn được chia thành tổng cộng chín quận trong thiên hạ. Mỗi khi trăng tròn chính là đêm yêu linh, lúc đó yêu linh ra ngoài đi săn mồi, chỉ ở trong trận pháp mới được bình an. Khoảng năm trăm năm lại có người từ bên ngoài tiến vào, mỗi lần đều gây gió tanh mưa máu; những người này gia nhập các quận, lấy chiến công thăng tiến và thường có biến hóa thần kỳ.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0496"]},{"id":"co-yeu-thanh-thien-yeu-quan","name":"Cổ yêu thành","cn":"","capDo":"thanh","parentId":"thien-yeu-quan-map","blurb":"Một trong những thành trì của Thiên Yêu quận, nơi Âu Dương Hoa từng học tập đạt trình độ nhất tinh; xa nhất lão từng đi tới.","detail":"Cổ yêu thành là một trong những thành trì của Thiên Yêu quận nhưng vẫn thuộc nơi man hoang. Âu Dương Hoa từng học tập ở đây nhưng chỉ đạt trình độ nhất tinh, không được quyền ở lại nên trở về bộ lạc làm trưởng lão. Đây là nơi xa nhất Âu Dương Hoa từng đi tới.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0496"]},{"id":"son-coc-ho-lo-thien-yeu-quan","name":"Sơn cốc hình hồ lô","cn":"","capDo":"khac","parentId":"thien-yeu-quan-map","blurb":"Nơi cư trú của bộ lạc Âu Dương Hoa; miệng hồ lô là cửa cốc, đáy hồ lô có vách đá xanh thẫm khảm ngọc yêu linh.","detail":"Sơn cốc hình hồ lô là nơi cư trú của bộ lạc Âu Dương Hoa thuộc nơi man hoang Thiên Yêu quận. Miệng hồ lô là cửa cốc, cây cối ít, mặt đất mọc cỏ êm ái, có khu cư dân quanh đống lửa. Tại đáy hồ lô có một vách đá màu xanh thẫm không ăn khớp bốn phía, trung tâm khảm khối ngọc yêu linh trắng hình lục giác. Cả cốc được trận pháp che chở khỏi yêu linh đi săn vào đêm trăng tròn.","theLucLienQuan":["Bộ lạc sơn cốc (Âu Dương Hoa)"],"nguon":["@c0496"]},{"id":"yeu-linh-khi-lang","name":"Yêu linh khí lãng","capDo":"khac","parentId":"the-gioi-dong-hai-yeu-linh","blurb":"Vùng đầy yêu linh vật biến trăm nghìn dạng, càng sâu yêu linh càng cao cấp.","detail":"Khu vực đầy yêu linh vật, mỗi con biến trăm nghìn dạng nhưng số sừng trên đầu không đổi — số sừng phản ánh sức mạnh. Càng đi sâu yêu linh càng cao cấp. Hai người Vương Lâm và Hắc y nam tử giao chiến ở rìa nên cấp bậc yêu linh thấp, đây cũng là lý do Hắc y nam tử sinh tồn ở rìa để hấp thụ yêu lực. Tiếng gào của Hắc y nam tử lúc luyện Ma cấm từng đánh văng khí lãng tạo khoảng trống chân không rộng chừng trăm trượng.","theLucLienQuan":[],"nguon":["@c0499"]},{"id":"vung-dat-yeu-linh","name":"Vùng đất yêu linh","cn":"","capDo":"vuc","parentId":"the-gioi-dong-hai-yeu-linh","blurb":"Vùng bí cảnh chia mười quận, mỗi quận phong ấn một Cổ yêu chi linh; năm ngàn năm mở một lần.","detail":"Vùng đất yêu linh chia làm mười quận, mỗi quận phong ấn một Cổ yêu chi linh. Cứ năm ngàn năm vùng mở một lần; dân cư gốc dù chiến công cao chỉ được cúng bái mà không thể dung hợp, chỉ người từ ngoài đến mới có cơ hội, và mấu chốt là yêu lực phải đủ. Người ngoài vào phải giết đối phương, hấp thu toàn bộ yêu lực để bớt đối thủ cạnh tranh.","theLucLienQuan":["Thiên Quỷ Đạo"],"nguon":["@c0502","@c0612"]},{"id":"cuu-tuyet-quan","name":"Cửu Tuyệt quận","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Quận trong vùng đất yêu linh có cổ yêu sinh ra sớm nhất, đến nay chưa ai dung hợp được.","detail":"Một trong chín quận của vùng đất yêu linh; cổ yêu nơi đây sinh ra sớm nhất nên hùng mạnh khó tưởng tượng, đến nay chưa ai dung hợp được.","theLucLienQuan":[],"nguon":["@c0502"]},{"id":"binh-nguyen-khe-ranh-yeu-linh","name":"Bình nguyên có khe rãnh","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Bình nguyên trong vùng đất yêu linh có vết nứt dài, nơi Thiên quỷ phản chủ ẩn núp.","detail":"Nơi Vương Lâm dịch chuyển ngàn dặm tới; có vết nứt dài chừng trăm trượng do một nhát chém từ trên không, nay chỉ còn khe nứt chưa đầy mười trượng, cỏ dại rậm rạp che lấp. Các âm hồn (gồm một đầu lân) xuất hiện lao tới ở đây, và Thiên quỷ suy yếu trốn trong khe rãnh.","theLucLienQuan":[],"nguon":["@c0502"]},{"id":"dong-bang-tay-bac-yeu-linh","name":"Đồng bằng Tây Bắc Yêu Linh chi địa","cn":"","capDo":"khac","parentId":"dong-hai-yeu-linh","blurb":"Vùng đồng bằng trống trải phía Tây Bắc Yêu Linh chi địa, nơi đặt bộ lạc Thiên Thủy với trận pháp viễn cổ mười dặm.","detail":"Bốn bề trống trải, dựa vào trận pháp viễn cổ mười dặm để chống Yêu Linh ban đêm. Bộ lạc Thiên Thủy đóng tại đây, sau bị Vương Lâm nhổ cả mảnh đất mang đi.","theLucLienQuan":["Bộ lạc Thiên Thủy"],"nguon":["@c0507"]},{"id":"co-yeu-thanh-dia-danh","name":"Cổ Yêu thành (địa danh)","cn":"","capDo":"thanh","parentId":"dong-hai-yeu-linh","blurb":"Thành lớn ở Yêu Linh chi địa có phủ Tả Dực tướng quân; nơi lão áo trắng làm chấp sự.","detail":"Có quân chế với Tả Dực tướng quân thống lĩnh; trong phủ có hàng Trưởng lão tu vi ngang Vương Lâm. Người từ bên ngoài tới có thể tìm chức vụ trong phủ Tướng quân.","theLucLienQuan":["Cổ Yêu thành / phủ Tả Dực tướng quân"],"nguon":["@c0507"]},{"id":"thung-lung-bo-lac-luyen-hon","name":"Thung lũng bộ lạc Luyện Hồn","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Trung tâm bộ lạc Luyện Hồn, nơi Vương Lâm cư trú và bố trí trận pháp.","detail":"Nơi Vương Lâm gầy dựng bộ lạc Luyện Hồn từ một bộ lạc nhỏ trong thung lũng. Trận pháp bảo hộ được mở rộng lên bốn mươi dặm, phủ màn sương đen tế dưỡng hồn phách; sau bốn năm phạm vi bộ lạc đạt gần ba trăm dặm.","theLucLienQuan":["Bộ lạc Luyện Hồn"],"nguon":["@c0508"]},{"id":"yeu-linh-chi-dia","name":"Yêu linh chi địa (chín quận Yêu linh)","cn":"","capDo":"vuc","parentId":null,"blurb":"Vùng đất rộng lớn gồm chín quận Yêu linh với vô số bộ lạc lớn nhỏ; hệ cảnh giới tính theo giáp.","detail":"Vùng đất Yêu linh có vô số bộ lạc lớn nhỏ trải rộng, chia thành chín quận. Hệ cảnh giới ở đây tính theo giáp: ba sao bằng một giáp, ba giáp Trúc Cơ, ba mươi giáp Kết Đan, ba trăm giáp Nguyên Anh, ba nghìn giáp Hóa Thần, ba vạn giáp Anh Biến, ba mươi vạn giáp Vấn Đỉnh. Có hai loại chức vụ: chức trong (Chấp sự, Trưởng lão — không binh quyền) và chức ngoài (Đô thống, thống lĩnh — có binh quyền). Thiên Yêu quận với Cổ Yêu thành nằm trong vùng này.","theLucLienQuan":["Cổ Yêu thành"],"nguon":["@c0509"]},{"id":"truc-thanh-lau","name":"Trúc Thanh lâu","capDo":"khac","parentId":"co-yeu-thanh-dia-danh","blurb":"Quán rượu trong Cổ Yêu thành với vò rượu khổng lồ phải bắc thang mới múc được.","detail":"Quán rượu náo nhiệt trong Cổ Yêu thành, nổi tiếng với rượu Trúc Thanh khắp Cửu quận. Giữa quán đặt một vò rượu khổng lồ rộng ba trượng, cao hai trượng, bốn phía bày thang để múc rượu. Cửa quán treo câu đối ‘Trúc thúy lan hinh nghênh cổ khách / Thanh mai vi hương tống tiên quân’. Vương Lâm cùng Thập Tam, Hổ Bào ngồi bàn cạnh cửa sổ và gọi ba hũ rượu tại đây.","theLucLienQuan":[],"nguon":["@c0512"]},{"id":"quan-doanh-yeu-binh","name":"Quân doanh yêu binh","cn":"","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Doanh trại yêu binh nơi Vương Lâm được truyền tống tới, vây quanh là hơn vạn yêu binh giáp đen.","detail":"Quân doanh xây bằng đá đen, chu vi ước trăm dặm, tường thành gia trì pháp thuật với yêu lực dao động. Vương Lâm xuất hiện ở chính giữa quân doanh; cách trăm trượng là hơn mười đội yêu binh giáp đen dồn sát khí về phía hắn như vạn thanh phi kiếm.","theLucLienQuan":["Quân doanh (dưới trướng Yêu Tương)"],"nguon":["@c0514"]},{"id":"quan-doanh-hac-giap-quan","name":"Quân doanh Hắc Giáp quân","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Doanh trại của một vạn yêu binh Hắc Giáp quân, có binh doanh, phòng ở Tư Mã Viêm và bãi đất trống nơi Vương Lâm ngồi thổ nạp.","detail":"Quân doanh Hắc Giáp quân là nơi đóng quân của một vạn yêu binh mặc giáp đen ở Yêu Linh chi địa. Trong doanh có căn phòng đơn giản được trận pháp bảo hộ, cạnh cắm cờ đen thêu hai chữ Tư Mã bằng kim tuyến — chỗ ở của phó thống lĩnh Tư Mã Viêm; quanh đó còn dấu vết kiến trúc cũ cho thấy trước kia không chỉ một phòng. Vương Lâm cùng Thập Tam và Hổ Bào không có chỗ ở nên ngồi thổ nạp trên bãi đất trống suốt ba ngày, trong khi yêu binh đêm đêm thao luyện phối hợp trận pháp.","theLucLienQuan":["Hắc Giáp quân"],"nguon":["@c0515"]},{"id":"vuc-sau-thuy-trieu","name":"Vực sâu nơi thủy triều","aliases":["Nơi đó"],"capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Vực sâu nơi thủy triều trong Yêu Linh chi địa, mục tiêu Diêu Tích Tuyết nhiều lần xông vào.","detail":"Mục tiêu mà Diêu Tích Tuyết cố xông vào theo kế hoạch của phụ thân; muốn tiến sâu cần tu vi ít nhất Vấn Đỉnh kỳ. Nàng đã thử bốn lần đều dừng ở cùng một vị trí. Phụ thân nàng cùng Thiên Vận tử từng tới vực sâu nơi thủy triều này sau khi hỏi được bí mật từ Yêu Đế, suy đoán nơi đó sáu phần là thật.","theLucLienQuan":[],"nguon":["@c0517"]},{"id":"co-son-quan-doanh-hac-giap-quan","name":"Cổ sơn (cách quân doanh ngàn dặm)","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Ngọn núi cổ cách quân doanh Hắc Giáp quân ngàn dặm, nơi Diêu Tích Tuyết hẹn gặp Vương Lâm lúc canh ba.","detail":"Núi cổ nằm cách quân doanh Hắc Giáp quân khoảng ngàn dặm. Diêu Tích Tuyết truyền âm hẹn Vương Lâm tới đỉnh cổ sơn này lúc canh ba; nàng mặc bạch y đứng đợi tới bình minh mà Vương Lâm không xuất hiện, dẫn tới việc nàng tức giận xông thẳng vào quân doanh.","theLucLienQuan":["Hắc Giáp quân"],"nguon":["@c0518"]},{"id":"huyet-to-dong-phu","name":"Huyết Tổ động phủ","capDo":"khac","parentId":"thien-van-tinh","blurb":"Động phủ của Huyết Tổ, phụ thân Diêu Tích Tuyết, cất giữ nhiều tiên ngọc.","detail":"Động phủ của Huyết Tổ Diêu Tinh Hải trên Thiên Vận tinh, nơi cất giữ nhiều tiên ngọc. Diêu Tích Tuyết hứa trao lệnh bài Huyết Phù để Vương Lâm tự đến đây lấy tiên ngọc làm thù lao sau khi ra khỏi Yêu Linh chi địa.","theLucLienQuan":["Thiên Vận Tông"],"nguon":["@c0519"]},{"id":"khong-gian-ton-thu-binh-dai-ton-long","name":"Không gian Tôn Thú (bình đài Tôn Long)","cn":"","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Không gian giống tinh không, không trời đất, chỉ toàn ánh sáng; có bình đài cao trăm trượng đặt trận pháp và con đường là thân giao long Tôn Long.","detail":"Nơi truyền tống trận của Huyết Tổ dẫn tới: một khoảng không như tinh không, không phân trời đất, khắp nơi tràn ánh sáng. Giữa đó là bình đài cao trăm trượng có trận pháp cùng quỹ tích với trận ẩn thân bảy pho tượng. Một con đường nhỏ uốn lượn lơ lửng trước mặt thực chất là cơ thể con giao long tên Tôn Long, do người dùng thần thông bố trí — cự thú không có trong ký ức Cổ Thần Đồ Ti.","theLucLienQuan":["Huyết Phủ"],"nguon":["@c0520"]},{"id":"con-duong-ton-long","name":"Con đường Tôn Long","capDo":"khac","parentId":"khong-gian-ton-thu-binh-dai-ton-long","blurb":"Con đường nối các bình đài mà Vương Lâm và Diêu Tích Tuyết men theo để tiến lên.","detail":"Con đường trong không gian Tôn Long, nối liền chuỗi bình đài cao bằng nhau. Vương Lâm và Diêu Tích Tuyết men theo con đường này để lần lượt vượt qua các bình đài có tượng đá phong ấn ký tự.","theLucLienQuan":[],"nguon":["@c0522"]},{"id":"binh-dai-tuong-da-ton-long","name":"Bình đài tượng đá (con đường Tôn Long)","capDo":"khac","parentId":"con-duong-ton-long","blurb":"Chuỗi bình đài cao bằng nhau, mỗi cái giữa có pho tượng đá phong ấn một ký tự.","detail":"Các bình đài cao bằng nhau dọc con đường Tôn Long, giữa mỗi cái có một pho tượng đá gần giống hệt nhau phong ấn một ký tự nét bút. Tượng tầng thứ nhất ẩn ký tự một nét; bình đài thứ ba có tượng thêm con mắt thứ ba ở mi tâm, ẩn ký tự hai nét màu vàng. Tượng được cấu thành hoàn toàn từ cấm chế chồng lớp, thức tỉnh tấn công khi có người đặt chân lên.","theLucLienQuan":[],"nguon":["@c0522"]},{"id":"dong-phu-tien-nhan-ton-long","name":"Động phủ tiên nhân (đường Tôn Long)","cn":"","capDo":"khac","parentId":"con-duong-ton-long","blurb":"Động phủ do một tiên nhân lưu lại nơi cuối đường Tôn Long, bỏ hoang nhiều năm; chỉ còn một tia linh hồn (Động Phủ Chi Linh) và ba đạo kiếm khí.","detail":"Phải cảm ngộ được kim phù và qua cửa đá đài thứ mười hai mới đủ tư cách vào thí luyện. Huyết Tổ biết được động phủ từ miệng một Yêu Đế; muốn tiếp trọn ba đạo kiếm khí phải có tu vi Vấn Đỉnh. Không vào được thì khách phải chết.","theLucLienQuan":[],"nguon":["@c0523"]},{"id":"cua-da-dai-thu-muoi-hai-ton-long","name":"Cửa đá hình mặt người (đài thứ mười hai)","cn":"","capDo":"khac","parentId":"con-duong-ton-long","blurb":"Đài thứ mười hai trên đường Tôn Long chỉ bằng nửa các đài khác, không có tượng đá mà là cánh cửa đá khổng lồ có khe hở tạo hình mặt người, dẫn vào động phủ tiên nhân.","detail":"Khi cửa mở, gió lạnh phun ra; Động Phủ Chi Linh hiện ra ở đây để khảo nghiệm. Vương Lâm vạch rõ đường Tôn Long thật chất chỉ có mười hai tầng phong ấn (Diêu Tích Tuyết nói dối là mười tám), qua cửa này là động phủ.","theLucLienQuan":[],"nguon":["@c0523"]},{"id":"dong-phu-tien-nhan-chu-nhan","name":"Động phủ tiên nhân (của “chủ nhân”)","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Động phủ tiên cấm trong Yêu Linh do một vị tiên nhân giấu mặt lập, toàn bộ dựng bằng tiên ngọc và phủ tiên cấm.","detail":"Qua cửa đá là dãy lầu các nguy nga như hoàng cung phàm nhân, nền lát tiên ngọc trong suốt. Bên trong có lò luyện đan khổng lồ, một căn lầu ba tầng phủ tiên cấm, hành lang tiên ngọc dài mười dặm chia ba hướng, hồ nước khô cạn, rừng trúc và một khu vườn trung tâm còn nguyên vẹn cấm chế. Toàn phủ trong lẫn ngoài đều có tiên cấm; mở được một phong ấn thì động phủ tự đóng cửa, người vào trước đó đều đã chết. Muốn rời đi phải mở được một đạo thảo ấn.","theLucLienQuan":[],"nguon":["@c0524"]},{"id":"khu-vuon-trung-tam-dong-phu","name":"Khu vườn trung tâm (động phủ tiên cấm)","capDo":"khac","parentId":"dong-phu-tien-nhan-chu-nhan","blurb":"Khu vườn còn nguyên vẹn cấm chế trong động phủ, kho báu duy nhất chưa ai phá được và là trung tâm của mọi cấm chế.","detail":"Nằm sau hành lang tiên ngọc rẽ về đường bên phải xuyên rừng trúc, khu vườn rộng có bàn tròn, bốn ghế đá, bầu rượu và vài ly. Trong chu vi mười trượng là cấm chế hoàn chỉnh chưa hề bị phá giải; đây là nơi tiền nhân mạnh nhất cũng phải rút lui vì nó là trung tâm của mọi cấm chế, một khi phát động sẽ kéo theo toàn bộ. Đường sinh tiến vào biến đổi không cố định và có thể đột ngột xoay ngược.","theLucLienQuan":[],"nguon":["@c0524"]},{"id":"tu-duong-rung-truc-dong-phu","name":"Từ đường trong rừng trúc","capDo":"khac","parentId":"dong-phu-tien-nhan-chu-nhan","blurb":"Một căn lầu giống từ đường trong đình viện phàm nhân, nằm phương xa trong động phủ giữa rừng trúc.","detail":"Khi định tiếp tục phá giải phong ấn, ánh mắt Vương Lâm chuyển lên rừng trúc phương xa và thấy một góc lan can bị trúc che, nhận ra phía trước còn một căn lầu giống từ đường trong đình viện của phàm nhân. Hắn không đến kiểm tra mà rời động phủ trước, ghi nhớ để quay lại khám phá vì xem động phủ là kho báu chứa nhiều bí mật.","theLucLienQuan":[],"nguon":["@c0525"]},{"id":"sau-cua-cung-yeu-tuong","name":"Sáu cửa dẫn vào cung Yêu Tướng","capDo":"khac","parentId":"co-yeu-thanh","blurb":"Sáu cửa canh phòng cẩn ngặt nối quân doanh tới cung điện Yêu Tướng ở trung tâm Cổ Yêu Thành.","detail":"Từ quân doanh đến cung Yêu Tướng phải qua sáu cửa. Khi truyền tống trận bị phong kín thì chỉ còn cách xông qua từng cửa. Mỗi cửa có trận pháp bao phủ vô hiệu hóa mọi phép thuấn di. Cửa thứ sáu cao chừng mười trượng, có bốn tường bao quanh, ánh sáng trận pháp cấm chế lóe ra; thủ vệ canh giữ và quát đuổi người lạ.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0527"]},{"id":"hac-lao-co-yeu-thanh","name":"Hắc lao (Cổ Yêu Thành)","capDo":"khac","parentId":"co-yeu-thanh","blurb":"Nhà ngục trong Cổ Yêu Thành với thủ vệ cực nghiêm, nơi tù nhân bị phế tu vi giam giữ.","detail":"Nhà ngục thuộc hệ thống quân doanh Cổ Yêu Thành, canh phòng cực nghiêm ngặt. Hổ Bào và Thập Tam đều từng bị Tư Mã Viêm phế tu vi rồi ném vào đây. Ba tháng sau khi bị giam, Hổ Bào mất tích bí ẩn dù hắc lao canh cực kỹ, khiến ngay cả Tư Mã Viêm cũng không hiểu cách hắn biến mất.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0527"]},{"id":"lanh-tho-yeu-linh","name":"Lãnh thổ Yêu Linh","capDo":"vuc","parentId":null,"blurb":"Vùng đất rộng lớn bao gồm chiến trường cổ và Thiên Yêu quận.","detail":"Lãnh thổ Yêu Linh là vùng đất bao trùm nhiều khu vực, trong đó có chiến trường cổ hung danh hiển hách ở phía Tây và Thiên Yêu quận có kinh thành cùng Yêu Đế.","theLucLienQuan":["Thiên Yêu quận","Yêu Vệ"],"nguon":["@c0530"]},{"id":"chien-truong-co-yeu-linh","name":"Chiến trường cổ (hoang mạc lãnh thổ Yêu Linh)","capDo":"khac","parentId":"lanh-tho-yeu-linh","blurb":"Hoang mạc khổng lồ hung danh hiển hách ở phía Tây Luyện Hồn cốc; vài trăm vạn dặm thi hài bể nát, mặt đất đỏ sậm, áp lực cực mạnh.","detail":"Chiến trường cổ là một hoang mạc khổng lồ trong lãnh thổ Yêu Linh, nằm ở phía Tây ngoài Luyện Hồn cốc, xa hơn cả Thiên Yêu quận. Tương truyền vài trăm vạn dặm khắp nơi là thi hài bể nát, mặt đất màu đỏ sậm, áp lực cực mạnh; bên ngoài có cấm chế vô hình ngăn cách với thế giới. Vô số linh hồn ngủ say trong đây, là nơi Hổ Bào luyện hóa linh hồn.","theLucLienQuan":[],"nguon":["@c0530"]},{"id":"hac-thap-muoi-tang","name":"Hắc tháp mười tầng","capDo":"khac","parentId":"chien-truong-co-yeu-linh","blurb":"Tòa tháp đen kịt mười tầng sâu trong chiến trường cổ, quầng sáng hắc sắc hấp thu mọi ánh sáng, uy nghiêm yêu dị.","detail":"Hắc tháp là tòa tháp đen k��t cao mười tầng nằm sâu trong chiến trường cổ, quầng sáng hắc sắc hấp thu mọi ánh sáng xung quanh, toát vẻ uy nghiêm yêu dị. Tầng cao nhất đặt bộ áo giáp cổ của chủ nhân; lão già hắc y vào tháp để quỳ báo cáo và nhận lệnh.","theLucLienQuan":[],"nguon":["@c0530"]},{"id":"luyen-hon-coc","name":"Luyện Hồn cốc (sơn cốc Vương Lâm dưỡng hồn)","capDo":"khac","parentId":null,"blurb":"Sơn cốc nơi Vương Lâm ngồi dưỡng hồn và truyền công pháp cho Thập Tam; chiến trường cổ nằm ở phía Tây ngoài cốc.","detail":"Sơn cốc gắn với bộ tộc Luyện Hồn, nơi Vương Lâm truyền sáu tầng Cự Linh Cửu Tu cho Thập Tam rồi ngồi một mình dưỡng hồn dưới hắc vụ do Tôn Hồn Phiên hóa thành. Phía Tây ngoài cốc, xa hơn cả Thiên Yêu quận, là chiến trường cổ trong lãnh thổ Yêu Linh.","theLucLienQuan":["Bộ lạc Luyện Hồn"],"nguon":["@c0530"]},{"id":"kinh-thanh-thien-yeu-quan","name":"Kinh thành Thiên Yêu quận","capDo":"thanh","parentId":"thien-yeu-quan-map","blurb":"Kinh đô Thiên Yêu quận, được ví đầm rồng hang hổ; điểm đến của Vương Lâm và Mạc Lực Hải sau khi rời Cổ Yêu thành.","detail":"Nơi tập trung các thế lực lớn trong quận, trong đó có nhánh Thiên Vận Tông tới lãnh thổ Yêu Linh và mười người Đại La Kiếm Tông mà Vương Lâm muốn truy hỏi về nơi Chu Dật bị phong ấn. Vương Lâm và Mạc Lực Hải tới đây qua ba truyền tống trận xuất phát từ Cổ Yêu thành.","theLucLienQuan":["Thiên Yêu quận","Cổ Yêu điện","Thiên Vận Tông","Đại La Kiếm Tông"],"nguon":["@c0531"]},{"id":"thien-yeu-thanh","name":"Thiên Yêu thành","capDo":"thanh","parentId":"thien-yeu-quan-map","blurb":"Kinh thành Thiên Yêu quận, do chín tòa thành nhỏ ghép thành, sáng sớm phủ long khí.","detail":"Kinh thành của Thiên Yêu quận, nằm phía bắc Thiên Yêu quận nơi nhiều đồng bằng đan xen, nhìn từ trên cao như chín con Cự Long quấn lấy nhau, đầu chín con rồng đều hướng về đầm Long Đàm. Thành thực chất do chín thành nhỏ ghép lại: tám thành ngoài phân theo bát quái, thành giữa là Đế Đô. Sáng sớm cả thành phủ một lớp sương mỏng từ chín dãy núi, được Yêu Đế gọi là long khí. Ngoài thành đặt mười tám truyền tống trận.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0532"]},{"id":"de-do-thien-yeu-thanh","name":"Đế Đô","capDo":"thanh","parentId":"thien-yeu-thanh","blurb":"Thành trung tâm Thiên Yêu thành, tẩm cung của Yêu Đế.","detail":"Tòa thành giữa của Thiên Yêu thành, là tẩm cung của Yêu Đế. Có sông bao quanh và tám cây cầu đá nối ra tám thành ngoài, bên trong đầy lầu các điêu lan ngọc thế. Là nơi diễn ra cuộc chiến Yêu tướng cứ ba trăm năm một lần.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0532"]},{"id":"long-dam-thien-yeu","name":"Long Đàm","capDo":"khac","parentId":"thien-yeu-thanh","blurb":"Đầm nước lớn phía bắc, nơi đầu chín con rồng địa hình cùng hướng tới.","detail":"Đầm nước lớn phía bắc Thiên Yêu quận, là chỗ đầu chín con Cự Long (địa hình đồng bằng) đều hướng về. Bên ngoài có đại quân trấn giữ; bên trong đặt Cổ Yêu Điện.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0532"]},{"id":"co-yeu-dien-long-dam","name":"Cổ Yêu Điện","capDo":"khac","parentId":"long-dam-thien-yeu","blurb":"Điện thờ bên trong Long Đàm, biểu tượng tinh thần của Thiên Yêu quận.","detail":"Tòa điện nằm bên trong Long Đàm, được xem là biểu tượng tinh thần của Thiên Yêu quận, bên ngoài có đại quân trấn giữ.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0532"]},{"id":"hong-thanh-thien-yeu","name":"Hồng thành","capDo":"thanh","parentId":"thien-yeu-thanh","blurb":"Thành ngoài cửa tây (vòng ngoài) của Thiên Yêu thành, nơi đặt phủ của Mạc Lệ Hải.","detail":"Một trong bốn thành vòng ngoài Vũ–Trụ–Hồng–Hoang, thuộc cửa tây của Thiên Yêu thành, là nơi đặt phủ của Yêu tướng Mạc Lệ Hải. Thành sầm uất; con đường lớn có một phần ba ở giữa là quân đạo dành riêng cho quân đội.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0532"]},{"id":"huyen-thanh-thien-yeu","name":"Huyền thành","capDo":"thanh","parentId":"thien-yeu-thanh","blurb":"Thành ngoài cửa tây (vòng trong) của Thiên Yêu thành.","detail":"Một trong bốn thành vòng trong Thiên–Địa–Huyền–Hoàng, thuộc cửa tây của Thiên Yêu thành, ở phía trong so với Hồng thành.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0532"]},{"id":"mac-phu","name":"Mạc phủ","cn":"","capDo":"khac","parentId":"de-do-thien-yeu-thanh","blurb":"Tòa phủ của Mạc Lệ Hải với đình viện, giả sơn, hồ nước trang nhã; Vương Lâm trú ở phía nam sau hòn giả sơn để tu luyện.","detail":"Một tòa phủ có đình viện, giả sơn và hồ nước bài trí trang nhã, là nơi ở của Yêu tướng Mạc Lệ Hải tại khu vực Thiên Yêu quận. Mạc Lệ Hải sắp xếp Vương Lâm trú ở phía nam sau hòn giả sơn, cắt cử hai quân sĩ hầu hạ. Vương Lâm tu luyện bốn ngày tại đây, thổ nạp Yêu lực và ngẫm Sát Lục Tiên Quyết.","theLucLienQuan":["Mạc Lệ Hải"],"nguon":["@c0533"]},{"id":"hong-lao","name":"Hồng lao","cn":"","capDo":"khac","parentId":"hong-thanh-thien-yeu","blurb":"Một trong tứ Đại Lao ngục của kinh đô, giam hơn vạn trọng phạm, canh gác nghiêm mật, phải có lệnh bài mới vào; ẩn chứa một cỗ yêu khí cường đại không kém Mạc Lệ Hải.","detail":"Hồng lao nằm trong Hồng thành, là một trong tứ Đại Lao ngục của kinh đô, chuyên giam giữ trọng phạm với hơn vạn tù nhân. Lao ngục tràn ngập tử ý và oán khí, canh gác cực kỳ nghiêm mật, không có lệnh bài không thể vào. Vương Lâm phát hiện trong Hồng lao ẩn chứa một cỗ yêu khí cường đại không kém Mạc Lệ Hải, và nhắm vào đây làm nơi giết chóc tu luyện bảy ngày.","theLucLienQuan":[],"nguon":["@c0535"]},{"id":"tu-dai-lao-nguc-kinh-do","name":"Tứ Đại Lao ngục (kinh đô)","cn":"","capDo":"khac","parentId":"de-do-thien-yeu-thanh","blurb":"Bốn đại lao ngục của kinh đô dùng để giam trọng phạm; Hồng lao là một trong số đó.","detail":"Tứ Đại Lao ngục là bốn lao ngục lớn của kinh đô, được canh gác nghiêm mật để giam giữ trọng phạm. Hồng lao nằm trong Hồng thành là một trong tứ Đại Lao ngục này.","theLucLienQuan":[],"nguon":["@c0535"]},{"id":"the-gioi-mau-mau-hong-lao","name":"Thế giới màu máu","aliases":["Thế giới máu tầng đáy Hồng lao"],"capDo":"khac","parentId":"hong-lao","blurb":"Thế giới độc lập màu máu do đế quân tự chế tạo ở tầng đáy Hồng lao, đầy hồ máu nuôi sát lục khí cho yêu kiếm.","detail":"Tầng dưới cùng của Hồng lao là một thế giới độc lập màu máu, do đế quân tự tay tạo ra. Khắp nơi là hồ máu, mỗi hồ chứa hàng ngàn người ngâm nửa thân, ngày đêm thổ nạp. Theo chu kỳ, toàn bộ người trong các hồ máu bừng tỉnh hô “Sát!” rồi lao vào chém giết lẫn nhau; người chết lại sống dậy từ hồ máu, thực chất chỉ là công cụ giết chóc. Sát lục khí sinh ra bị bầu trời hút đi, dồn về nuôi yêu kiếm ngân long của yêu đế. Vương Lâm tu luyện sát lục chi tâm tại đây.","theLucLienQuan":["Hồng lao","Yêu đế"],"nguon":["@c0536"]},{"id":"kiem-cac-de-do-thien-yeu","name":"Kiếm Các","cn":"","capDo":"khac","parentId":"de-do-thien-yeu-thanh","blurb":"Gác kiếm nằm trong hoàng cung Đế Đô ở trung tâm Thiên Yêu Thành; sàn trống, có trận pháp huyết sắc khổng lồ cắm Đế Kiếm.","detail":"Kiếm Các nằm trong hoàng cung Đế Đô ở trung tâm Thiên Yêu Thành; nền sàn trống trải, giữa có trận pháp huyết sắc khổng lồ cắm thanh kiếm hình con rắn (Đế Kiếm). Khi Đế Kiếm tự rút khỏi trận nhãn bay về Hồng Thành, cả Thiên Yêu Thành chấn động; sau một tháng nó đắc ý quay về cắm lại nơi đây.","theLucLienQuan":["Thiên Yêu Quận"],"nguon":["@c0537"]},{"id":"the-gioi-huyet-sac-hong-lao","name":"Thế giới huyết sắc (Hồng Lao)","cn":"","capDo":"khac","parentId":"hong-lao","blurb":"Thế giới máu bên trong Hồng Lao, đầy hồ máu, tu sĩ tan-tái sinh hấp thu sát niệm; ngân long Đế Kiếm ngự trị.","detail":"Thế giới màu máu bên trong Hồng Lao, đầy hồ máu, tu sĩ liên tục tan thành huyết nhục rồi tái sinh trong hồ máu để hấp thu sát niệm — nơi luyện Sát Lục. Ngân long (Đế Kiếm) ngự trị hấp thu sát vụ chuyển thành sinh cơ. Bị Vương Lâm phá vỡ phạm vi lớn khi sát lục khí bạo phát.","theLucLienQuan":["Thiên Yêu Quận"],"nguon":["@c0537"]},{"id":"huyen-thanh-thien-yeu-quan","name":"Huyền Thành","cn":"","capDo":"thanh","parentId":"thien-yeu-quan-map","blurb":"Một trong tám thành ngoài Thiên Yêu Thành; có Huyền Thành soái phủ (phủ phó soái Huyền Thành).","detail":"Huyền Thành là một trong tám thành ngoài của Thiên Yêu Thành; có Huyền Thành soái phủ tức phủ phó soái Huyền Thành. Cảnh đêm rực rỡ, quân s�� áo giáp đi lại. Mạc Lệ Hải dẫn Vương Lâm tới cửa tây Huyền Thành rồi vào đình viện soái phủ.","theLucLienQuan":["Thiên Yêu Quận"],"nguon":["@c0537"]},{"id":"vu-thanh-thien-yeu-quan","name":"Vũ Thành","cn":"","capDo":"thanh","parentId":"thien-yeu-quan-map","blurb":"Một trong các thành thuộc Thiên Yêu Thành; nơi Mặc Phi ở trong một biệt viện cùng hai đệ tử.","detail":"Vũ Thành là nơi Yêu Tương Mặc Phi ở trong một biệt viện cùng hai đệ tử đeo đại kiếm.","theLucLienQuan":["Thiên Yêu Quận","Hỏa Yêu Quận"],"nguon":["@c0537"]},{"id":"quy-phi-lau-de-do","name":"Quý Phi Lâu","cn":"","capDo":"khac","parentId":"de-do-thien-yeu-thanh","blurb":"Lầu trong hoàng cung Đế Đô, nơi người mặc hoàng bào và nữ tử xinh đẹp quan sát Đế Kiếm bay qua.","detail":"Quý Phi Lâu nằm trong hoàng cung, nơi người mặc hoàng bào và nữ tử xinh đẹp đứng quan sát ngân quang Đế Kiếm bay qua khi nó rời trận nhãn.","theLucLienQuan":["Thiên Yêu Quận"],"nguon":["@c0537"]},{"id":"ben-song-hoa-thuyen-hong-thanh","name":"Bến sông họa thuyền (Hồng Thành)","cn":"","capDo":"khac","parentId":"hong-thanh-thien-yeu","blurb":"Bến sông nơi Vương Lâm ngồi nghe tiếng đàn của nữ tử mắt đen trên họa thuyền mỗi ngày.","detail":"Bến sông nơi Vương Lâm ngồi cầm bầu rượu nghe tiếng đàn bi thương của nữ tử mắt đen trên họa thuyền; nơi hắn đối ẩm từ xa với thanh niên áo xanh mang yêu lực.","theLucLienQuan":["Thiên Yêu Quận"],"nguon":["@c0537"]},{"id":"soai-phu-pho-soai-huyen-thanh","name":"Soái phủ phó soái Huyền Thành","cn":"","capDo":"khac","parentId":"thien-yeu-thanh","blurb":"Phủ đệ của phó soái Huyền Thành, có vườn hoa kỳ dị quý giá.","detail":"Phủ đệ của phó soái Huyền Thành tại Thiên Yêu Thành, có vườn hoa kỳ dị quý giá mà phó soái cả đời mê đắm. Nơi Mạc Lệ Hải dẫn Vương Lâm tới bái kiến tranh chức phó soái.","theLucLienQuan":["Yêu tộc Thiên Yêu Thành (hệ Yêu Tướng - Yêu Soái)"],"nguon":["@c0538"]},{"id":"de-do-kiem-cac","name":"Đế Đô Kiếm Các","cn":"","capDo":"khac","parentId":"thien-yeu-thanh","blurb":"Kiến trúc ở trung tâm Thiên Yêu Thành, đặt trận pháp giam Đế Kiếm.","detail":"Kiến trúc nằm ở trung tâm Thiên Yêu Thành, đặt trận pháp giam giữ và trấn áp Đế Kiếm. Người mặc hoàng bào trấn áp Đế Kiếm tại đây, cấm nó tới Hồng Lao phá hoại.","theLucLienQuan":["Yêu tộc Thiên Yêu Thành (hệ Yêu Tướng - Yêu Soái)"],"nguon":["@c0538"]},{"id":"huyet-dam-vo-tan","name":"Huyết đàm (vô tận)","cn":"","capDo":"khac","parentId":null,"blurb":"Thế giới huyết sắc nơi người trong đó chém giết, chết rồi sống lại; sát niệm dũng mãnh nuôi sát khí.","detail":"Huyết đàm vô tận là một thế giới huyết sắc, sát niệm dũng mãnh nuôi sát khí trong người tu luyện ở đó. Người bên trong chém giết nhau, chết rồi sống lại lặp đi lặp lại. Ngân long Đế Kiếm dùng nơi này để trút giận, giết đi sống lại nam tử tóc đen nhiều lần.","theLucLienQuan":[],"nguon":["@c0539"]},{"id":"hong-lao-yeu-de","name":"Hồng Lao","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Yêu Đế không cho ngân long đi phá hoại; chuyện Hồng Lao tạm chưa nhắc tới.","detail":"Yêu Đế không cho Ngân long Đế Kiếm đi phá hoại Hồng Lao, lại bắt nó im lặng vài ngày, khiến nó trút giận trong huyết đàm.","theLucLienQuan":[],"nguon":["@c0539"]},{"id":"hoa-yeu-quan-map","name":"Hỏa Yêu Quận","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi Yêu Tướng Vu Sâm lấy sát lục tu luyện hằng năm.","detail":"Quận vùng Yêu Linh, nơi Yêu Tướng Vu Sâm — Yêu Tướng duy nhất không có thành trì — hằng năm lấy sát lục đạo tu luyện tới đỉnh.","theLucLienQuan":[],"nguon":["@c0543"]},{"id":"quang-truong-thien-yeu-mon","name":"Quảng trường Thiên Yêu Môn","capDo":"khac","parentId":"de-do-thien-yeu-thanh","blurb":"Quảng trường vạn trượng đầy cấm chế, nơi diễn ra đại hội Yêu Tướng.","detail":"Quảng trường vạn trượng của Thiên Yêu Môn, nơi diễn ra đại hội Yêu Tướng. Khắp nơi bố trí cấm chế khiến độn thổ khó hơn bên ngoài gấp mười lần. Có khán đài bốn phía cùng hai khán đài nam bắc dành cho tám Yêu Soái; Kiếm Linh của Đế Kiếm từng ngồi ẩn trên mái cung điện của quảng trường.","theLucLienQuan":["Thiên Yêu Môn"],"nguon":["@c0544"]},{"id":"mac-phu-thien-yeu-thanh","name":"Mạc phủ","cn":"","capDo":"khac","parentId":"de-do-thien-yeu-thanh","blurb":"Phủ đệ của Mạc Lệ Hải, nơi diễn ra trận Mạt Dương đấu Vương Lâm; có mật thất bế quan, giả sơn, quân sĩ canh giữ.","detail":"Phủ đệ của Yêu Tướng Mạc Lệ Hải. Trong mật thất bế quan, mười bảy pho tượng hình người to bằng bàn tay vờn quanh kết hợp yêu khí thành vòng tuần hoàn. Mạt Dương phá cửa, giết quân sĩ, vượt qua người thấp bé và ba lão già để vào trao chiến thư, rồi khiêu chiến Vương Lâm tại đây.","theLucLienQuan":["Mạc phủ"],"nguon":["@c0541"]},{"id":"co-dao-sanh-duong","name":"Cổ Đạo (sảnh đường)","cn":"","capDo":"khac","parentId":"de-do-thien-yeu-thanh","blurb":"Sảnh đường nơi hẹn quyết chiến ba ngày sau theo chiến thư Mặc Phi gửi Mạc Lệ Hải.","detail":"Địa điểm hẹn quyết chiến giữa Mặc Phi và Mạc Lệ Hải, ba ngày sau khi chiến thư được trao, nằm ngoài sảnh đường Cổ Đạo.","theLucLienQuan":["Mạc phủ"],"nguon":["@c0541"]},{"id":"quang-truong-yeu-co-thien-yeu-thanh","name":"Quảng trường Yêu Cổ","cn":"","capDo":"khac","parentId":"thien-yeu-thanh","blurb":"Quảng trường cao vạn trượng có cấm chế tại Thiên Yêu Thành, đặt Yêu Cổ làm khảo nghiệm.","detail":"Sân đấu cao vạn trượng có cấm chế, nơi đặt chiếc trống Yêu Cổ làm khảo nghiệm cao nhất. Khi trống vang, mặt đất quảng trường nứt theo vòng tròn trăm trượng, nhiều khán giả bị chấn thương phun máu, vài người chấn động mất mạng.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0547"]},{"id":"long-dam-co-yeu-chi-linh","name":"Long Đàm","cn":"","capDo":"khac","parentId":"thien-yeu-quan-map","blurb":"Nơi trong Thiên Yêu quận có Cổ Yêu Chi Linh; sinh vật trong Long Đàm xếp trên cả Yêu Cổ về địa vị.","detail":"Long Đàm là địa danh trong Thiên Yêu quận, nơi có Cổ Yêu Chi Linh — sinh linh được xưng “thuyết pháp chi đạo, thiên địa chi tôn”. Sinh vật trong Long Đàm xếp trên cả Yêu Cổ về địa vị và giá trị tại Thiên Yêu quận.","nguon":["@c0549"]},{"id":"thap-den-chien-truong-vien-co","name":"Tháp đen trên chiến trường viễn cổ","cn":"","capDo":"khac","parentId":null,"blurb":"Ngọn tháp màu đen đang gầm rống hấp thu âm hồn nơi chiến trường viễn cổ, cách Thiên Yêu thành rất xa; nơi thực thể giáp đen phát thần niệm và ra đòn.","detail":"Ở nơi rất xa Thiên Yêu thành, trên tầng cao nhất một ngọn tháp đen đang hấp thu âm hồn của chiến trường viễn cổ. Mũ sắt của một bộ giáp đen lóe u quang khiến bầu trời quanh tháp dao động; từ đây vang ra thần niệm “Nghịch tu… Tốt lắm!” và tiếng hừ lạnh, dùng cổ âm hàn đánh vỡ kim giáp Kim Ô Húc từ xa.","theLucLienQuan":[],"nguon":["@c0550"]},{"id":"con-song-thuyen-ngoai-de-do","name":"Con sông và con thuyền ngoài Đế Đô","cn":"","capDo":"khac","parentId":"de-do-thien-yeu-thanh","blurb":"Con thuyền neo trên sông bên ngoài Đế Đô, nơi người thanh niên và người con gái đánh đàn ngồi quan sát khảo nghiệm.","detail":"Trên thuyền neo trên sông bên ngoài Đế Đô, người thanh niên từng uống rượu cả đêm với Vương Lâm ngồi ở mũi thuyền uống rượu, tự hỏi Vương Lâm sẽ chọn ra sao rồi đứng dậy nhìn về Đế Đô kỳ vọng. Người con gái đánh đàn ngồi yên không gảy đàn. Tiếng quát của người thanh niên từ đây khiến Kim Ô Húc run rẩy.","theLucLienQuan":[],"nguon":["@c0550"]},{"id":"tam-toa-ngoai-thanh-thien-yeu","name":"Tám tòa ngoại thành (Thiên Yêu Thành)","capDo":"khac","parentId":"thien-yeu-thanh","blurb":"Tám khu ngoại thành quanh Thiên Yêu Thành, nơi người thanh niên phân thân tám người tới di dời toàn bộ cư dân trước thiên uy.","detail":"Tám tòa ngoại thành bao quanh Thiên Yêu Thành. Trước khi thiên uy giáng lâm, người thanh niên trên thuyền hoa phân thân một thành tám, thuấn di tới tám tòa ngoại thành thi triển đại pháp thuật di chuyển toàn bộ cư dân ra nơi khác để tránh kiếp nạn.","theLucLienQuan":[],"nguon":["@c0553"]},{"id":"de-do-thien-yeu-thanh-554","name":"Đế Đô Thiên Yêu thành","cn":"","capDo":"thanh","parentId":"thien-yeu-quan-map","blurb":"Tòa thành Đế Đô của Thiên Yêu quận tồn tại rất nhiều vạn năm, bị thiên uy thiên kiếp Vương Lâm nghiền nát hoàn toàn thành tro bụi, chỉ thánh vật Yêu Cổ sót lại.","detail":"Đế Đô Thiên Yêu thành là tòa thành Đế Đô của Thiên Yêu quận, sừng sững tồn tại rất nhiều vạn năm, có hoàng cung Đế Đô và quảng trường vạn trượng. Khi thiên kiếp giáng đòn trừng phạt thứ hai lên Vương Lâm, thiên uy nghiền nát hoàn toàn cả tòa thành thành tro bụi, đất đai chia năm xẻ bảy; duy nhất thánh vật Yêu Cổ sót lại. Năm lão già con cháu Cổ Yêu cũng từ lòng đất nơi đây phóng lên.","theLucLienQuan":["Thiên Yêu quận","Cổ Yêu"],"nguon":["@c0554"]},{"id":"long-dam-co-yeu-thanh","name":"Long Đàm (do Cổ Yêu lập)","capDo":"khac","parentId":"thien-yeu-quan-map","blurb":"Nơi Cổ Yêu dùng thần thông tạo ra để giáo dục con dân Thiên Yêu quận, cũng là chốn giam phạt.","detail":"Long Đàm là nơi Cổ Yêu lập ra trong Thiên Yêu quận để giáo dục con dân, sao chép theo các nơi tương tự của tám quận Yêu Linh khác. Đồng thời là chốn giam phạt với mức án leo thang từ trăm năm đến cả đời. Cổ Yêu hẹn Vương Lâm ba tháng sau đến Long Đàm gặp mặt; Vân Độn được giao đưa Vương Lâm tới.","theLucLienQuan":["Thiên Yêu quận","Cổ Yêu"],"nguon":["@c0555"]},{"id":"yeu-co-vat-the-nguon","name":"Yêu Cổ (vật thể nguồn Cổ Yêu)","capDo":"khac","parentId":"thien-yeu-quan-map","blurb":"Tấm da/cấu trúc vốn là thân thể Cổ Yêu năm xưa, nơi Cổ Yêu thức tỉnh và không thể rời xa.","detail":"Khi thức tỉnh, Cổ Yêu đã ở trong Yêu Cổ và cảm nhận tấm da Yêu Cổ vốn là của mình năm xưa. Vì sự ràng buộc này, Cổ Yêu không thể rời xa Yêu Cổ, mới phải dùng thần thông tạo Long Đàm để giáo dục con dân từ xa. Cùng dạng với các vật thể nguồn của tám tồn tại không hoàn chỉnh ở tám Yêu quận khác.","theLucLienQuan":["Cổ Yêu","Thiên Yêu quận"],"nguon":["@c0555"]},{"id":"than-bi-dong-phu-van-dinh","name":"Thần bí động phủ (nơi tiến Vấn Đỉnh)","capDo":"khac","parentId":null,"blurb":"Động phủ Vương Lâm vào bằng lệnh bài, chọn làm nơi an toàn nhất để tiến Vấn Đỉnh.","detail":"Sau thiên kiếp, Vương Lâm dùng lệnh bài tiến vào thần bí động phủ — có nhiều đài đá liên tiếp và chỗ bầu rượu. Hắn đổ hết tiên ngọc thành núi nhỏ làm nhiên liệu, nuốt Vấn Đỉnh Chi Tinh của Chu Dật và hoàn thành tiến Vấn Đỉnh tại đây sau quá trình rất lâu.","theLucLienQuan":[],"nguon":["@c0555"]},{"id":"hoa-yeu-quan-556","name":"Hỏa Yêu quận","cn":"","capDo":"vuc","parentId":"lanh-tho-yeu-linh","blurb":"Một trong các quận thuộc lãnh thổ Yêu Linh; nơi Vương Lâm bị truyền tống lệch tới sau khi tiến Vấn Đỉnh.","detail":"Hỏa Yêu quận là một vùng lãnh thổ Yêu Linh. Khi Vương Lâm dùng lệnh bài động phủ thuấn di nhưng bị vòng xoáy đen can nhiễu, hắn bị truyền tống lệch và hiện ra trên một đồng bằng khổng lồ rộng không biết bao nhiêu dặm trong Hỏa Yêu quận.","theLucLienQuan":[],"nguon":["@c0556"]},{"id":"vuon-thang-tien-qua-yeu-linh","name":"Vườn Thăng Tiên Quả (sau cấm chế)","cn":"","capDo":"khac","parentId":"lanh-tho-yeu-linh","blurb":"Khu vườn hoang vu được bảo vệ bằng hàng ngàn cấm chế phản ứng dây chuyền, trồng dày đặc không dưới một vạn cây Thăng Tiên Quả.","detail":"Chốn hoang vu cây cỏ khô héo, đất nứt nẻ, được bảo vệ bằng hàng ngàn cấm chế cẩu thả nhưng số lượng lớn có phản ứng dây chuyền và huyễn thuật che giấu — ngay cả Yêu Tương cũng khó cưỡng phá. Bên trong là đồng bằng chia mảnh trồng trọt, mùi thơm quỷ dị, trồng dày đặc không dưới một vạn cây Thăng Tiên Quả. Vương Lâm dùng thủ pháp phá tiên cấm động phủ xuyên qua không kích hoạt.","theLucLienQuan":["Lãnh thổ Yêu Linh"],"nguon":["@c0557"]},{"id":"chien-truong-vien-co","name":"Chiến trường viễn cổ","capDo":"khac","parentId":null,"blurb":"Nơi có hắc tháp chứa luồng thần thức của người mặc áo giáp; Vương Lâm đang tiến về phía đó nhưng còn cách rất xa.","detail":"Chiến trường viễn cổ là vùng đất xa xôi, trên đó có hắc tháp phát ra luồng thần thức của người mặc áo giáp. Luồng thần thức này từng nhiều lần công kích Vương Lâm; nay khi thấy Vương Lâm không chết mà ngày càng mạnh, hắn lo sợ Vương Lâm chắc chắn sẽ có ngày tiến đến đây.","theLucLienQuan":[],"nguon":["@c0559"]},{"id":"ma-vuc-tinh-cau","name":"Ma Vực","capDo":"tinh-cau","parentId":"thien-van-tinh","blurb":"Tinh cầu Ma Vực trên Thiên Vận Tinh, nơi Mạc Tổ tu luyện.","detail":"Ma Vực là một tinh cầu nằm trên Thiên Vận Tinh, nơi cường giả Mạc Tổ tu vi Âm Dương Hư Thực nhị ý cư ngụ. Từ đây ba đệ tử thân truyền của Mạc Tổ xuất phát, trong đó hai người vượt mức tư cách vào mảnh đất Yêu Linh.","theLucLienQuan":["Mạc Tổ (sư đồ Ma Vực)"],"nguon":["@c0559"]},{"id":"van-yeu-son","name":"Vạn Yêu sơn","cn":"","capDo":"khac","parentId":null,"blurb":"Đường ranh giới giữa Hỏa Yêu quận và Thiên Yêu quận, sương mù dày đặc, nơi bố trí bao vây Vương Lâm.","detail":"Vạn Yêu sơn là dải núi tạo thành đường ranh giới giữa Hỏa Yêu quận và Thiên Yêu quận, quanh năm sương mù dày đặc. Hai sườn núi có hai tòa thành đối diện: Thiên Dật Thành của Hỏa Yêu quận và Dung Hỏa Thành của Thiên Yêu quận. Đây là nơi Hỏa Yêu quận chọn để bày trận bao vây diệt Vương Lâm.","theLucLienQuan":["Hỏa Yêu quận","Thiên Yêu quận"],"nguon":["@c0560"]},{"id":"thien-dat-thanh","name":"Thiên Dật Thành","cn":"","capDo":"thanh","parentId":"van-yeu-son","blurb":"Tòa thành của Hỏa Yêu quận trên sườn Vạn Yêu sơn, nơi tập kết mười vạn Yêu binh.","detail":"Thiên Dật Thành nằm trên một sườn của Vạn Yêu sơn, thuộc Hỏa Yêu quận. Trong thành có mười vạn Yêu binh chờ lệnh, hơn mười Yêu tướng đứng trên thành cùng Phó soái tọa trấn, làm cứ điểm cho trận vây diệt Vương Lâm.","theLucLienQuan":["Hỏa Yêu quận"],"nguon":["@c0560"]},{"id":"dung-hoa-thanh","name":"Dung Hỏa Thành","cn":"","capDo":"thanh","parentId":"van-yeu-son","blurb":"Tòa thành của Thiên Yêu quận trên sườn Vạn Yêu sơn, đối diện Thiên Dật Thành.","detail":"Dung Hỏa Thành nằm trên sườn núi đối diện thuộc Thiên Yêu quận, ngó sang Thiên Dật Thành của Hỏa Yêu quận qua dải Vạn Yêu sơn.","theLucLienQuan":["Thiên Yêu quận"],"nguon":["@c0560"]},{"id":"thien-van-thanh-pho-soai","name":"Thiên Văn Thành","cn":"","capDo":"thanh","parentId":null,"blurb":"Nơi Phó soái Hỏa Yêu quận có chuyện riêng muốn đến trước khi bị giữ lại tọa trấn Vạn Yêu sơn.","detail":"Thiên Văn Thành là điểm đến mà Phó soái Hỏa Yêu quận dự định ghé vì chuyện riêng, nhưng vừa đến Vạn Yêu sơn thì nhận lệnh Yêu Đế phải ở lại mấy ngày diệt Vương Lâm. Chuyện riêng và mục đích của hắn tại đây chưa được tiết lộ.","theLucLienQuan":["Hỏa Yêu quận"],"nguon":["@c0560"]},{"id":"dong-phu-ngam-long-dam-thien-yeu","name":"Động phủ ngầm dưới Long Đàm","capDo":"khac","parentId":"long-dam-thien-yeu","blurb":"Động thiên ngăn bởi yêu mạc sâu trong Long Đàm, một động phủ ngầm khổng lồ có pho tượng Cổ Yêu.","detail":"Sâu trong Long Đàm bên ngoài thành Thiên Yêu có một động thiên ngăn bởi yêu mạc — một động phủ ngầm khổng lồ. Trong có pho tượng toàn thân tối đen giống Cổ Yêu, hai mắt lóe ánh sáng yêu dị dung nhập vào cơ thể tu sĩ. Đây là nơi Vương Lâm khoanh chân ngồi luyện, khống chế và mưu nuốt một Tán ma khổng lồ.","theLucLienQuan":[],"nguon":["@c0567"]},{"id":"thanh-tung-dao-hoa-yeu-quan","name":"Thành Tùng Đào (quận Hỏa Yêu)","cn":"","capDo":"thanh","parentId":"hoa-yeu-quan-556","blurb":"Thành biên giới quận Hỏa Yêu, đích đến của đại quân cánh tả quận Thiên Yêu và Vương Lâm.","detail":"Thành Tùng Đào nằm ở biên giới quận Hỏa Yêu, nơi Mặc Phi (nay là Phó soái) cùng cánh quân bên trái đang tiến tới. Đại quân cánh tả quận Thiên Yêu (ngàn vạn yêu binh, ba chính soái Thiên–Trụ–Hoang, ba phó soái Hồng–Huyền–Hoàng) cũng thẳng đến đây; Vương Lâm định tới tìm Mặc Phi.","theLucLienQuan":["Hỏa Yêu Quận","Thiên Yêu quận"],"nguon":["@c0570"]},{"id":"quan-hoa-yeu","name":"Quận Hỏa Yêu","cn":"","capDo":"khac","parentId":null,"blurb":"Nơi người bộ lạc Luyện Hồn đến hấp thu hồn yêu binh đã chết để tu hành hiệu quả.","detail":"Nơi người bộ lạc Luyện Hồn đến hấp thu hồn của yêu binh đã chết để tu hành hiệu quả hơn; ai muốn đi phải qua khảo hạch đích thân của Âu Dương Hoa.","theLucLienQuan":["Bộ lạc Luyện Hồn"],"nguon":["@c0573"]},{"id":"thanh-trang-chuong-khi-bien-gioi-hoa-yeu-kim-yeu","name":"Tòa thành trắng trong chướng khí (biên giới Hỏa Yêu - Kim Yêu)","cn":"","capDo":"thanh","parentId":null,"blurb":"Tòa thành bốn phía núi đá trắng cao khoảng mười trượng ẩn sâu trong dãy núi chướng khí biên giới quận Hỏa Yêu và Kim Yêu — sào huyệt của Lão tổ.","detail":"Vùng biên giới quận Hỏa Yêu và Kim Yêu có một dãy núi lớn quanh năm chướng khí, nơi cả quân Hỏa Yêu lẫn Kim Yêu đều không quản. Sâu trong chướng khí có tòa thành bốn phía núi đá trắng cao khoảng mười trượng, mang cảm giác thần bí — sào huyệt của Lão tổ, nơi ra lệnh truy bắt Vương Lâm.","theLucLienQuan":["Quận Hỏa Yêu","Quận Kim Yêu"],"nguon":["@c0574"]},{"id":"quan-do-thanh-co-yeu","name":"Quận đô thành Cổ Yêu","cn":"","capDo":"thanh","parentId":null,"blurb":"Nơi Vương Lâm mất tích hai mươi năm trước, theo lời bóng đen bẩm báo với Lão tổ.","detail":"Quận đô thành Cổ Yêu là nơi Vương Lâm — nay làm sứ giả Cổ Yêu — đã mất tích hai mươi năm trước. Thông tin này được thuộc hạ của Lão tổ tra ra và bẩm báo.","theLucLienQuan":["Cổ Yêu"],"nguon":["@c0574"]},{"id":"vung-chuong-khi-lien-minh","name":"Vùng chướng khí (căn cứ Liên minh)","cn":"","capDo":"khac","parentId":"quan-thien-yeu-faction","blurb":"Vùng vạn dặm ngập chướng khí có linh tính, căn cứ ẩn của Tu sĩ Liên minh.","detail":"Vùng chướng khí trong phạm vi vạn dặm ở chỗ giao nhau giữa Hoả Yêu Quận và Thiên Yêu Quận (Tôn Vân Sơn khai là giao giới phía bắc Hoả Yêu Quận và Kim Yêu Quận). Chướng khí nồng đậm có linh tính, là căn cứ ẩn của Tu sĩ Liên minh với tòa thành sâu bên trong. Sau khi Vương Lâm dùng Hồn Tuyền hút sạch chướng khí, nơi này lần đầu trong vô số năm lộ ra dưới ánh mặt trời.","theLucLienQuan":["Tu sĩ Liên minh"],"nguon":["@c0576"]},{"id":"kim-yeu-quan","name":"Kim Yêu Quận","cn":"","capDo":"khac","parentId":null,"blurb":"Một trong chín quận; Liên minh tu sĩ nằm ở giao giới phía bắc của Hoả Yêu Quận và Kim Yêu Quận.","detail":"Một trong chín quận Yêu Linh. Theo lời khai của Tôn Vân Sơn, căn cứ Liên minh tu sĩ nằm ở chỗ giao nhau phía bắc của Hoả Yêu Quận và Kim Yêu Quận, nơi quanh năm ngập chướng khí, cực kỳ bí mật.","theLucLienQuan":["Tu sĩ Liên minh"],"nguon":["@c0576"]},{"id":"toa-thanh-trang-lao-to-lien-minh","name":"Toà thành màu trắng","cn":"","capDo":"thanh","parentId":null,"blurb":"Toà thành trắng sừng sững, đại bản doanh của Lão Tổ; nơi hơn trăm tu sĩ phiêu phù bên ngoài và Tiên vệ bay ra.","detail":"Phía trước Vương Lâm hiện ra một toà thành màu trắng sừng sững. Hơn trăm tu sĩ phiêu phù bên ngoài thành, khiếp sợ trước khí thế của Vương Lâm. Đây là đại bản doanh của Lão Tổ Liên minh — nơi các Tiên vệ áo đen bay ra nghênh chiến.","nguon":["@c0577"]},{"id":"toa-thanh-trang-lao-gia-tien-luong","name":"Toà thành màu trắng (lão già Toà thành trắng)","capDo":"khac","parentId":null,"blurb":"Căn cứ của lão già tự xưng người Tiên giới; bị Hoàng tuyền của Vương Lâm quét sập.","detail":"Nơi lão già thấp bé ẩn náu, bạo phát tiên lực tinh thuần phản kích. Hoàng tuyền của Vương Lâm dựng cột lớn chống đỡ, tản thành lốc xoáy quét ra khiến Toà thành màu trắng sụp đổ.","theLucLienQuan":["Tiên giới"],"nguon":["@c0578"]},{"id":"de-do-hoa-yeu-quan","name":"Đế đô Hoả Yêu Quận","cn":"","capDo":"thanh","parentId":"hoa-yeu-quan-map","blurb":"Toà thành trống trải sau trăm năm chiến tranh, mặt đất đỏ lầy do máu, sương xám và yêu khí phủ kín.","detail":"Kinh đô Hoả Yêu Quận, từng phồn hoa ngang Thiên Yêu Thành. Sau gần trăm năm tử chiến với Thiên Yêu Quận, mặt đất nhuộm hồng bởi máu, đầy hài cốt và tử khí tạo thành sương mù xám phủ kín. Yêu Đế đã tự tham chiến khiến kinh đô trống không, chỉ còn lại Thánh địa Yêu Cốc; toàn bộ bị Cổ Yêu phong ấn bằng yêu mạc trải mười dặm ngoài thành.","theLucLienQuan":["Hoả Yêu Quận"],"nguon":["@c0584"]},{"id":"thanh-dia-yeu-coc-hoa-yeu-quan","name":"Thánh địa Yêu Cốc (Hoả Yêu Quận)","cn":"","capDo":"khac","parentId":"de-do-hoa-yeu-quan","blurb":"Thánh địa nằm sâu trong đế đô Hoả Yêu Quận, phần duy nhất còn lại khi kinh đô trống không.","detail":"Yêu Cốc của Hoả Yêu Quận nằm sâu trong đế đô; yêu khí dày đặc và tử khí tràn ngập toả ra từ đây khiến đế đô như toà thành trong sương mù. Đây là nơi Cổ Yêu Hoả Yêu Quận trú ngụ và phóng thần thức đối đầu Vương Lâm.","theLucLienQuan":["Hoả Yêu Quận"],"nguon":["@c0584"]},{"id":"trieu-tich-tham-uyen","name":"Triều Tịch thâm uyên","cn":"","capDo":"khac","parentId":"thuy-yeu-quan","blurb":"Hiểm địa nhiều hung hiểm trong lời đồn, mục tiêu chung của cả nhóm; nghi nằm sau vết nứt trong vân hải.","detail":"Nơi hiểm địa nhiều hung hiểm theo lời đồn, được Đỗ Kiến nghi là nằm sau vết nứt mà hắn phát hiện trong vân hải tại Vân Vụ sơn hải. Vương Lâm đã tra xét trước bằng thủy tinh của Bối La, biết có mấy nơi với tu vi của hắn vẫn phải mạo hiểm.","theLucLienQuan":[],"nguon":["@c0589"]},{"id":"van-vu-son-hai","name":"Vân Vụ sơn hải","cn":"","capDo":"khac","parentId":"thuy-yeu-quan","blurb":"Vùng mây mù đồ sộ mỹ lệ của Thủy Yêu quận, Đỗ Kiến khen hơn tiên giới một bậc; chứa vết nứt nghi là Triều Tịch thâm uyên.","detail":"Vùng mây mù đồ sộ mỹ lệ tại Thủy Yêu quận, được Đỗ Kiến khen còn hơn tiên giới một bậc. Trong vân hải có một vết nứt mà Đỗ Kiến phát hiện, nghi chính là Triều Tịch thâm uyên trong lời đồn.","theLucLienQuan":[],"nguon":["@c0589"]},{"id":"khe-phong-an-chu-dat","name":"Cái khe (khe phong ấn Chu Dật)","cn":"","capDo":"khac","parentId":"trieu-tich-tham-uyen","blurb":"Cái khe nơi Chu Dật bị Lăng Thiên Hậu phong ấn mấy trăm năm, thuộc Triều Tịch vực.","detail":"Nơi Lăng Thiên Hậu phong ấn Chu Dật bằng trận pháp cùng bốn thành kiếm Nguyên Thần và ba quả cầu thần niệm. Sau khi Chu Dật dùng bản mệnh kiếm khí phá tan trận pháp, cái khe sụp xuống và hắn thoát ra cùng Vương Lâm.","theLucLienQuan":[],"nguon":["@c0595"]},{"id":"ho-sau-day-trieu-tich-vuc","name":"Cái hố sâu (đáy Triều Tịch vực)","cn":"","capDo":"khac","parentId":"trieu-tich-tham-uyen","blurb":"Hố tối thần thức không xuyên thấu nơi đáy Triều Tịch vực, có lực hút thường trực, cứ năm ngàn năm bộc phát một lần.","detail":"Đáy Triều Tịch vực là hành lang uốn lượn vòng quanh, giữa có hố sâu tối om quái dị mà thần thức không xuyên thấu được. Hố phát ra lực hút nhỏ nhưng thường trực, cuốn vụn đất đá; cứ năm ngàn năm bộc phát một lần tạo lực hút khổng lồ xoáy theo thông đạo bay ra — Vương Lâm đoán đây là nguồn thủy triều Đông Hải. Hố còn có lực quái dị ảnh hưởng tâm thần và phát ra sương mù tím; nghi liên quan tới bức tranh thần bí. Rơi vào hố thì không có khả năng ra.","theLucLienQuan":[],"nguon":["@c0596"]},{"id":"qua-cau-suong-mu","name":"Quả cầu sương mù","capDo":"khac","parentId":null,"blurb":"Khối sương mù phía xa không ngừng co lại, giấu người sống và lệnh bài bên trong.","detail":"Một khối sương mù phía xa không tỏa ra khí tức, không ngừng co lại từ trăm trượng xuống một trượng rồi bảy thước. Bên trong giấu một đệ tử Đại La kiếm tông còn sống và một lệnh bài đang dần ngưng hiện. Tham Lang sau khi thoát vây liền tham lam cất bước tiến về phía nó.","theLucLienQuan":["Đại La Kiếm Tông"],"nguon":["@c0602"]},{"id":"vuc-sau-ho-sau-day-vuc-c0604","name":"Vực sâu / hố sâu đáy vực","cn":"","capDo":"khac","parentId":null,"blurb":"Vực sâu nơi Vương Lâm đấu pháp với Tham Lang, lực cản cực mạnh, đáy có hố sâu vô hạn với lực hút khác thường gần hành lang quay về.","detail":"Vương Lâm tháo chạy xuống vực sâu để kéo giãn khoảng cách chờ Chu Dật. Lực cản dưới vực cực mạnh; ��áy vực có một hố sâu vô hạn với lực hút khác thường mà Vương Lâm từng vào trước đây nên biết quy luật, vận tiên lực nương một bên lao xuống an toàn. Hố này gần hành lang quay về, là địa điểm then chốt cho lối thoát.","theLucLienQuan":[],"nguon":["@c0604"]},{"id":"ho-sau-luc-hut-c0605","name":"Hố sâu lực hút","cn":"","capDo":"khac","parentId":"vuc-sau-ho-sau-day-vuc-c0604","blurb":"Hố sâu có lực hút cực mạnh tăng dần theo độ sâu, vách đá vạn trượng dựng đứng sâu không thấy đáy, phủ màn sương đen.","detail":"Nơi giam giữ cuộc đối đầu giữa Vương Lâm và Thái Cổ Lôi Long. Càng xuống sâu lực hút càng mạnh, vách đá vạn trượng dựng đứng sâu không thấy đáy, phủ màn sương đen khiến thần thức không tản ra được. Lôi cầu của Lôi Long phun ra cũng bị chệch quỹ đạo và hút thẳng xuống đáy hố.","theLucLienQuan":[],"nguon":["@c0605"]},{"id":"khe-trong-vach-da-c0605","name":"Cái khe trong vách đá","cn":"","capDo":"khac","parentId":"ho-sau-luc-hut-c0605","blurb":"Miệng khe rộng chừng một trượng trong vách đá hố sâu, ít chịu lực hút.","detail":"Một miệng khe rộng chừng một trượng nằm trong vách đá hố sâu, ít chịu ảnh hưởng của lực hút bên ngoài. Vương Lâm phát hiện nhờ chỗ hụt của Tiên Kiếm và Loan Đao dưới chân, liền lao vào trú thân, thu hồi pháp bảo và dùng làm nơi nuốt Thái Cổ Lôi Long rồi hấp thu lôi lực.","theLucLienQuan":[],"nguon":["@c0605"]},{"id":"tang-da-truyen-tong-tran-c0605","name":"Tảng đá có Truyền Tống Trận","cn":"","capDo":"khac","parentId":"ho-sau-luc-hut-c0605","blurb":"Tảng đá nhô ra khoảng mười trượng dưới đáy hố, bên trên có một Truyền Tống Trận, thoáng hiện rồi chìm vào màn sương đen.","detail":"Tảng đá lớn nhô ra khoảng mười trượng dưới đáy hố sâu, bên trên có một Truyền Tống Trận. Nhờ thanh khí Lôi Long phát sáng, Vương Lâm thoáng thấy nó rồi tảng đá lại chìm vào màn sương đen, không kịp nhìn rõ — gợi ý một lối truyền tống ẩn dưới đáy vực.","theLucLienQuan":[],"nguon":["@c0605"]},{"id":"la-thien-tinh-vuc","name":"La Thiên tinh vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực Vương Lâm dự định tới để đề cao tu vi, do nữ tử trong tranh dụ dẫn.","detail":"La Thiên tinh vực là nơi nữ tử trong tranh dụ Vương Lâm tới với mục đích riêng còn bỏ ngỏ. Vương Lâm chỉ tin nàng ba phần song vẫn quyết tới để đề cao tu vi cho ngang Thiên Vận Tử rồi quay về tra xét động phủ.","theLucLienQuan":[],"nguon":["@c0613","@c0616"]},{"id":"dong-lam-tinh","name":"Đông Lâm tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu có Hướng gia mà Vương Lâm định ghé dò thân phận nữ tử trong tranh.","detail":"Đông Lâm tinh là nơi đặt Hướng gia. Vương Lâm dự định tới đây dò thân phận nữ tử trong tranh vì lão tổ tộc nàng được cho là có thể khiến Uyển nhi sống lại.","theLucLienQuan":["Hướng gia (Đông Lâm tinh)"],"nguon":["@c0613"]},{"id":"vuc-sau-trieu-tich-thuy-yeu-quan","name":"Vực sâu triều tịch (Thủy Yêu quận)","cn":"","capDo":"khac","parentId":"thuy-yeu-quan","blurb":"Nơi Vương Lâm lao xuống; có lực hút mạnh đưa người tiến sâu vào hành lang dẫn tới hố sâu, dưới đáy hố có dòng xoáy.","detail":"Vực sâu triều tịch nằm tại Thủy Yêu quận, có lực hút cực mạnh đưa người tiến sâu vào hành lang dẫn tới hố sâu. Vương Lâm hòa hợp với lực hút này, dùng Thất Tinh kiếm trận tăng tốc lao xuống. Dưới đáy hố có dòng xoáy thông tới La Thiên tinh vực.","theLucLienQuan":[],"nguon":["@c0614"]},{"id":"dong-xoay-thong-la-thien-tinh-vuc","name":"Dòng xoáy thông tới La Thiên tinh vực","cn":"","capDo":"khac","parentId":"vuc-sau-trieu-tich-thuy-yeu-quan","blurb":"Dưới đáy hố sâu, lực lượng ngăn cách giữa hai tinh vực cực mạnh; Vương Lâm dung nhập rời đi qua đây.","detail":"Dòng xoáy nằm dưới đáy hố sâu vực triều tịch, chứa một cỗ lực lượng mênh mông ngăn cách giữa hai tinh vực, thông tới La Thiên tinh vực. Huyết Tổ năm xưa từng thử vào nhưng thất bại. Vương Lâm bước lên dòng xoáy, dung nhập rời đi, lực lượng phun ra khiến cả thần thức đám lão quái phải lùi lại.","theLucLienQuan":[],"nguon":["@c0614"]},{"id":"la-van-tinh-vuc","name":"La Vân Tinh Vực","cn":"","capDo":"vuc","parentId":"tu-dai-tien-gioi","blurb":"Tinh vực thuộc Lôi chi tiên giới, nơi Vương Lâm hiện ra sau khi qua trận lốc xoáy như truyền tống trận.","detail":"Một tinh vực thuộc Lôi chi tiên giới trong tứ đại tiên giới phong-vũ-lôi-điện. Vương Lâm sau khi dung nhập trận lốc xoáy đã hiện ra tại tinh không xa lạ này, không phải Liên Minh Tinh Vực quê hương. Tại đây có những sinh vật như Minh vụ trùng toả sương độc; cũng là nơi sức mạnh Lôi hệ của hắn (Thiên Lôi từ Thái Cổ Lôi Long) phát huy uy lực.","theLucLienQuan":["Nhiễm gia"],"nguon":["@c0615"]},{"id":"lien-minh-tinh-vuc","name":"Liên Minh Tinh Vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực quê hương của Vương Lâm, nơi đa số tu sĩ không biết tới các tinh vực bên ngoài.","detail":"Quê hương của Vương Lâm. Ở đây, trừ số rất ít người, đại đa số tu sĩ không biết sự tồn tại của các tinh vực bên ngoài, tưởng tinh không chỉ có Tu Chân Liên Minh — sự thật về tứ đại tiên giới bị giấu diếm.","theLucLienQuan":["Tu Chân Liên Minh"],"nguon":["@c0615","@c0625"]},{"id":"nhiem-van-tinh","name":"Nhiễm Vân Tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tu chân tinh nơi Nhiễm gia cư trú trong La Thiên Tinh Vực.","detail":"Một tu chân tinh thuộc La Thiên Tinh Vực, là nơi cư trú của Nhiễm gia. Bốn người được Vương Lâm cứu (Nhiễm Nguyệt, Nhiễm Thần, Nhiễm Phong và Tôn Tuyết Sơn) đều là người Nhiễm Vân Tinh đến thí luyện.","theLucLienQuan":["Nhiễm gia"],"nguon":["@c0615"]},{"id":"hop-van-thanh","name":"Hợp vân thánh","cn":"","capDo":"khac","parentId":"la-thien-tinh-vuc","blurb":"Địa danh cách chỗ vây hãm khoảng bảy ngày đường về hướng bắc; Vương Lâm hỏi tìm tới.","detail":"Địa danh tại La Thiên Tinh Vực mà Vương Lâm truyền âm hỏi đường tới. Tôn Tuyết Sơn đáp rằng nơi này cách chỗ nhóm bị vây khoảng bảy ngày đường về hướng bắc, và xin được dẫn đường để đền ơn cứu mạng.","theLucLienQuan":[],"nguon":["@c0615"]},{"id":"tu-dai-tien-gioi","name":"Tứ đại tiên giới phong-vũ-lôi-điện","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Bốn đại tiên giới phong, vũ, lôi, điện; mỗi giới có các tinh vực riêng.","detail":"Bốn đại tiên giới phong-vũ-lôi-điện, mỗi giới sở hữu các tinh vực riêng. Tu sĩ La Thiên Tinh Vực đa phần biết tới tầng bậc này, còn tu sĩ Liên Minh Tinh Vực thì hầu hết không hay. Lôi chi tiên giới — chứa La Vân Tinh Vực nơi Vương Lâm vừa đến — là một trong tứ đại tiên giới này.","theLucLienQuan":[],"nguon":["@c0615"]},{"id":"khe-nut-ho-sau-yeu-linh","name":"Khe nứt dưới hố sâu vùng đất Yêu Linh","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Khe rộng vài trượng nơi Vương Lâm mắc kẹt ba năm; bên ngoài là hố sâu lực hút cực mạnh không quy tắc, đáy hố có Truyền Tống Trận thần bí.","detail":"Khe nứt rộng vài trượng nằm trong hố sâu thuộc vùng đất Yêu Linh, nơi Vương Lâm ngồi tu suốt ba năm. Hơn hai năm trước, khi hắn vuốt thân Cự Phú, lực hút của hố sâu bùng nổ như gió lốc lan vào nửa cái khe. Lực hút ngoài khe mạnh gấp vô số lần, xé da thịt và rút cả tơ linh lực. Trên tảng đá lớn ở bãi đá xiêu vẹo cách khe khoảng hai mươi trượng phía dưới, đối diện cái khe, có một Truyền Tống Trận cổ xưa thần bí. Vương Lâm chờ lực hút suy yếu để rời đi, cuối cùng lao tới Truyền Tống Trận này.","theLucLienQuan":[],"nguon":["@c0610"]},{"id":"la-thien-tinh-vuc-map","name":"La Thiên tinh vực","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Quê hương nữ tử trong tranh, một mảnh tinh không vô số tu chân tinh nằm sau dòng xoáy; chính là Lôi tiên giới trong Tứ đại tiên giới.","detail":"La Thiên tinh vực là một thế giới khác gồm vô số tu chân tinh, nằm sau dòng xoáy ở đáy hố vùng yêu linh. Nơi này không có tông phái, chỉ có các gia tộc tu chân (như Hướng gia ở Đông Lâm tinh). La Thiên tinh vực chính là Lôi tiên giới — một trong Tứ đại tiên giới. Thiên Nghịch châu xuất hiện sớm nhất ở đây rồi quỷ dị biến mất.","theLucLienQuan":["Hướng gia (Đông Lâm tinh)"],"nguon":["@c0612"]},{"id":"tu-dai-tien-gioi-phong-vu-loi-dien","name":"Tứ đại tiên giới (Phong, Vũ, Lôi, Điện)","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Bốn mảnh tiên giới phân theo các thông đạo dẫn tới tiên vực viễn cổ, là chỗ tu sĩ cao giai phi thăng.","detail":"Xưa có một tiên vực thần bí, về sau bỏ rơi tu sĩ và rời tinh không, chỉ để lại các thông đạo phân thành Tứ đại tiên giới: Phong, Vũ, Lôi, Điện. La Thiên tinh vực chính là Lôi tiên giới; Vũ tiên giới thuộc Liên Minh Tinh Vực là nơi Thiên Nghịch châu từng xuất hiện sau khi biến mất ở La Thiên tinh vực. Đây là chỗ tu sĩ cao giai phi thăng.","theLucLienQuan":[],"nguon":["@c0612"]},{"id":"dong-lam-tinh-map","name":"Đông Lâm tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc-map","blurb":"Tinh cầu nơi có Hướng gia, thuộc La Thiên tinh vực.","detail":"Đông Lâm tinh là một tinh cầu thuộc La Thiên tinh vực (Lôi tiên giới), nơi tọa lạc của Hướng gia — gia tộc của nữ tử trong bức tranh.","theLucLienQuan":["Hướng gia (Đông Lâm tinh)"],"nguon":["@c0612"]},{"id":"nhiem-van-tinh-la-thien","name":"Nhiễm Vân Tinh","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tinh cầu màu thủy lam ở bình nguyên phía bắc La Thiên Tinh Vực, biển chiếm hơn nửa, linh lực tràn đầy.","detail":"Nhiễm Vân Tinh là tinh cầu màu thủy lam ở phía bắc La Thiên Tinh Vực, biển chiếm hơn nửa, linh lực tràn đầy hơn xa quê hương Chu Tước của Vương Lâm. Toàn tinh cầu chỉ có ba phương thế lực, mỗi thế lực một Vấn Đỉnh (một trung kỳ, hai sơ kỳ). Vương Lâm chọn nơi này ẩn nấp tránh đám Thiên Vận Tinh truy đuổi; thành Tôn gia nằm tại đây.","theLucLienQuan":["Nhiễm gia","Tôn gia"],"nguon":["@c0616"]},{"id":"thien-huyen-tinh","name":"Thiên Huyễn Tinh","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Một trong năm đại chủ tinh, lệ thuộc bắc vực Nhiễm Vân Tinh, là bắc vực chủ tinh La Thiên Tinh Vực.","detail":"Thiên Huyễn Tinh là một trong năm đại chủ tinh, lệ thuộc bắc vực, xung quanh có nhiều sao lệ thuộc. Đây là bắc vực chủ tinh của La Thiên Tinh Vực, nơi có Huyễn gia và Hứa gia danh giá. Cái tên Thiên Huyễn khiến Vương Lâm nhớ tới Liễu Mi từng tu luyện Thiên Huyễn Vô Tình Đạo.","theLucLienQuan":["Huyễn gia","Hứa gia"],"nguon":["@c0616"]},{"id":"dong-lam-sat-tinh","name":"Đông Lâm Tinh","aliases":["Đông Lâm Sát Tinh","La Thiên Đông Vực"],"capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"La Thiên Đông Vực, còn gọi Đông Lâm Sát Tinh, nơi quỷ dị hư vô mờ mịt, ác mộng đè nặng dân La Thiên Tinh Vực.","detail":"Đông Lâm Tinh chính là La Thiên Đông Vực, còn có tên Đông Lâm Sát Tinh — nơi quỷ dị hư vô mờ mịt lúc hiện lúc ẩn. Người đi ra từ đó đều tàn nhẫn, từng có tu sĩ giết cả một gia tộc, là ác mộng đè nặng dân La Thiên Tinh Vực. Khi Vương Lâm hỏi về nơi này, bốn người dẫn đường đều tái nhợt hoảng loạn.","theLucLienQuan":[],"nguon":["@c0616"]},{"id":"ton-gia-thanh-nhiem-van","name":"Thành Tôn gia","capDo":"thanh","parentId":"nhiem-van-tinh-la-thien","blurb":"Tòa thành trì cự thạch xanh đề hai chữ Tôn gia trên Nhiễm Vân Tinh, nơi Vương Lâm ẩn nấp.","detail":"Thành Tôn gia là tòa thành trì cự thạch xanh đề hai chữ Tôn gia trên Nhiễm Vân Tinh. Thành chủ yếu là phàm nhân nhưng tu sĩ nhiều, phố xá bán vật dụng tu sĩ. Thành bắc yên tĩnh, linh khí dày, có nhiều người sống một mình, mỗi phòng có cấm chế phòng hộ; một ngọn núi đá ba trượng treo bảy tám lệnh bài đen làm động phủ cho thuê, có thanh niên Nguyên Anh kỳ canh giữ. Vương Lâm thuê phòng thứ năm phía tây ở đây.","theLucLienQuan":["Tôn gia"],"nguon":["@c0616"]},{"id":"thanh-dong-thanh-tu-si-c0618","name":"Thành đông (thành tu sĩ)","cn":"","capDo":"thanh","parentId":null,"blurb":"Khu cuối thành tập trung cửa hàng lớn san sát, đa số tu sĩ lui tới, nơi đặt Bảo Hợp Lâu và Thanh Trúc Các.","detail":"Khu thành đông của một thành tu sĩ, cuối thành tập trung cửa hàng lớn san sát, đa số tu sĩ lui tới, dân thường ít. Tập tục nơi đây là đặt khối linh thạch lớn chưa luyện hóa trước cửa để phô trương sức mạnh. Nơi đặt Bảo Hợp Lâu và Thanh Trúc Các.","theLucLienQuan":["Bảo Hợp Lâu","Thanh Trúc Các"],"nguon":["@c0618"]},{"id":"thanh-bac-nui-da-c0618","name":"Thành bắc & núi đá ngoài thành","cn":"","capDo":"thanh","parentId":null,"blurb":"Khu thành bắc với núi đá ngoài thành, nơi tu sĩ ngồi thổ nạp hấp thụ linh khí.","detail":"Khu thành bắc của thành tu sĩ, ngoài thành có núi đá nơi Vương Lâm và các tu sĩ ngồi thổ nạp hấp thụ linh khí.","theLucLienQuan":[],"nguon":["@c0618"]},{"id":"thanh-tay-c0618","name":"Thành tây (phường thị tự do)","cn":"","capDo":"thanh","parentId":null,"blurb":"Khu thành tây có phường thị tự do mua bán pháp bảo, vật liệu, song tu sĩ Anh Biến trở lên hiếm.","detail":"Khu thành tây của thành tu sĩ, có phường thị tự do nơi tu sĩ mua bán pháp bảo, vật liệu, song tu sĩ Anh Biến trở lên hiếm, không phải nơi buôn bán tốt nhất.","theLucLienQuan":["Phường thị tự do thành tây"],"nguon":["@c0618"]},{"id":"thanh-bac-ton-gia-nhiem-van-tinh","name":"Thành Bắc (tòa thành Tôn Gia)","cn":"","capDo":"thanh","parentId":"nhiem-van-tinh-la-thien","blurb":"Chỗ ở của Vương Lâm tại thành Bắc trên Nhiễm Vân Tinh, linh khí đậm đặc hơn ngoại thành, do Tôn Gia quản.","detail":"Tòa thành nơi Vương Lâm trú tại thành Bắc trên Nhiễm Vân Tinh, linh khí đậm đặc hơn ngoại thành, do Tôn Gia quản lý. Gần chỗ ở của hắn có ngọn núi nơi một nữ giả nam tĩnh tọa thổ nạp.","theLucLienQuan":["Tôn Gia"],"nguon":["@c0621"]},{"id":"thanh-truc-cac-nhiem-van-tinh","name":"Thanh Trúc Các (cửa hàng giao dịch)","capDo":"khac","parentId":"nhiem-van-tinh-la-thien","blurb":"Cửa hàng nơi Vương Lâm giao dịch bán ngọc giản kế thừa gương đồng cho lão già Anh Biến.","detail":"Thanh Trúc Các là nơi Vương Lâm bán ngọc giản kế thừa của gương đồng (ngụy tiên bảo) lấy hơn một vạn tiên ngọc cùng số dư túi trữ vật. Lão già Anh Biến cũng rời đi từ đây sau khi không hứng thú với cây trâm.","theLucLienQuan":[],"nguon":["@c0620"]},{"id":"thanh-ton-gia-nhiem-van-tinh","name":"Thành Tôn gia (chi nhánh)","capDo":"thanh","parentId":"nhiem-van-tinh-la-thien","blurb":"Khu thành có tòa nhà lớn của Tôn gia chi nhánh, nơi Vương Lâm đại náo và ép bồi thường.","detail":"Trung tâm thành Tôn gia có tòa nhà lớn của gia tộc (chi nhánh). Người trung niên chạy về đây kêu cứu rồi ngã gục; Vương Lâm đáp xuống điềm tĩnh, vung lốc xoáy cuốn văng tu sĩ Tôn gia và giáng uy áp khổng lồ lên tòa nhà lớn buộc cả gia tộc chống đỡ.","theLucLienQuan":["Tôn gia (chi nhánh)"],"nguon":["@c0620"]},{"id":"hai-duong-dong-bo-nhiem-van-tinh","name":"Hải dương đông bộ Nhiễm Vân Tinh","capDo":"khac","parentId":"nhiem-van-tinh-la-thien","blurb":"Biển cả bao la ở đông bộ Nhiễm Vân Tinh, nơi sâu nhất có nam tử tóc dài ẩn tu dưới đáy biển.","detail":"Đông bộ Nhiễm Vân Tinh có hải dương bao la. Nơi sâu nhất của biển cả, một nam tử tóc dài khoanh chân ngồi ẩn tu, mắt lóe tinh quang như hai ngọn đèn. Hắn cảm nhận sự xuất hiện của vị tu sĩ Vấn Đỉnh (Vương Lâm), nhìn không thấu tu vi đối phương, hiểu cái liếc cảnh cáo rồi rời đáy biển bay đi.","theLucLienQuan":[],"nguon":["@c0620"]},{"id":"la-thien-tinh-vuc-q06","name":"La Thiên Tinh Vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực ở Vực Bắc nơi Huyễn Gia cư ngụ, gồm Ngũ Đại Tinh ở bắc vực; nơi Lôi tiên giới mở ra.","detail":"Tinh vực thuộc Vực Bắc, gồm Ngũ Đại Tinh ở bắc vực, là nơi Huyễn Gia và nhiều gia tộc coi trọng huyết mạch sinh sống. Lôi tiên giới mở định kỳ trên La Thiên Tinh Vực, Lôi Đỉnh do Lôi Tiên Điện khống chế.","theLucLienQuan":["Huyễn Gia","Lôi Tiên Điện"],"nguon":["@c0622"]},{"id":"thien-huyen-tinh-bac-vuc","name":"Thiên Huyễn Tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc-q06","blurb":"Tinh cầu giống ngọc lưu ly, một trong Ngũ Đại Tinh ở bắc vực, quê hương Huyễn Gia, đích đến của sư phụ và Liễu Mi.","detail":"Tinh cầu trông giống ngọc lưu ly, là một trong Ngũ Đại Tinh ở bắc vực La Thiên Tinh Vực và là quê hương gia tộc Huyễn Gia. Sư phụ Liễu Mi đưa nàng về đây sau vài ngàn năm chưa quay lại, nhờ La Thiên Thạch của tổ tiên.","theLucLienQuan":["Huyễn Gia"],"nguon":["@c0622"]},{"id":"thien-van-thanh-nhiem-van-tinh","name":"Thiên Vận Thành","cn":"","capDo":"thanh","parentId":"nhiem-van-tinh","blurb":"Thành trên Nhiễm Vân Tinh nơi Tôn Tích chạy tới sau khi tu luyện dưới đáy biển; có thành Bắc, thành Đông.","detail":"Tòa thành trên Nhiễm Vân Tinh, gồm thành Bắc (nơi Tôn Lăng phụ trách phòng thủ và Vương Lâm áp đảo Tôn Tích) và thành Đông (có Bảo Hợp Lâu). Tôn Tích chạy tới đây sau khi kết thúc tu luyện dưới đáy biển để thăm dò Vương Lâm.","theLucLienQuan":["Tôn Gia"],"nguon":["@c0622"]},{"id":"loi-tien-gioi","name":"Lôi tiên giới","cn":"","capDo":"khac","parentId":"la-thien-tinh-vuc-q06","blurb":"Nơi mở định kỳ trên La Thiên Tinh Vực, có Lôi Đỉnh bị Lôi Tiên Điện khống chế; suất đi là điều kiện Tôn Tích đưa ra.","detail":"Một thế giới mở định kỳ trên La Thiên Tinh Vực, bên trong có Lôi Đỉnh bị Lôi Tiên Điện khống chế. Mỗi lần mở chỉ người La Thiên Tinh Vực và gia tộc ghi chép trong Lôi Tiên Điện mới được tuyển chọn vào. Suất đi Lôi tiên giới trăm năm sau là điều kiện Tôn Tích đưa ra để cầu Vương Lâm trợ giúp.","theLucLienQuan":["Lôi Tiên Điện"],"nguon":["@c0622"]},{"id":"bao-hop-lau-thanh-dong-nhiem-van","name":"Bảo Hợp Lâu (thành Đông)","cn":"","capDo":"khac","parentId":"thanh-dong-thanh-tu-si-c0618","blurb":"Tửu lâu kiêm sảnh đấu giá bốn tầng ở thành Đông, sản nghiệp của Nhiễm Gia; nơi diễn ra kỳ bán đấu giá bát phẩm đan dược.","detail":"Bảo Hợp Lâu là tòa lâu bốn tầng ở thành Đông, vốn là sản nghiệp của Nhiễm Gia, kiêm chức năng sảnh đấu giá. Đại sảnh đấu giá nằm ở tầng hai; các phòng riêng trên lầu bốn nhìn thẳng xuống sàn đấu giá. Vương Lâm theo Tôn Tích vào phòng đầu tiên bên trái lầu bốn, dùng thần thức phát hiện một hình bóng già nua ở lầu ba. Đây là nơi bày bán bát phẩm đan dược khởi điểm một vạn tiên ngọc, cũng là cái bẫy Nhiễm Gia giăng cho Vương Lâm.","theLucLienQuan":["Nhiễm Gia","Tôn Gia"],"nguon":["@c0623"]},{"id":"dong-lam-tinh-la-thien","name":"Đông Lâm tinh","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc-q06","blurb":"Tinh cầu nơi Tôn Thái luân lạc gần trăm năm, có ba gia tộc Hứa-Lữ-Lưu cực mạnh.","detail":"Nằm trong La Thiên tinh vực. Có ba gia tộc lớn mạnh nhất là Hứa, Lữ, Lưu — sâu không lường, tùy ý phái một trưởng lão liền có thể diệt sạch Nhiễm Vân tinh. Được Tôn Thái mô tả là một địa ngục hỗn loạn, thế giới máu tanh. Vương Lâm dò hỏi nơi này có Hướng gia hay không.","theLucLienQuan":["Hứa gia (Đông Lâm tinh)","Lữ gia","Lưu gia (Đông Lâm tinh)"],"nguon":["@c0625"]},{"id":"tu-thanh-tinh","name":"Tứ Thánh tinh","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu nơi Chu Tước tử đời thứ nhất tách Chu Tước tinh ra; bản thân là chi nhánh Tứ Thánh tông.","detail":"Chu Tước tử đời thứ nhất nghe đồn bắt đầu tách Chu Tước tinh ra từ Tứ Thánh tinh; mà Tứ Thánh tinh cũng chỉ là một chi nhánh của Tứ Thánh tông.","nguon":["@c0625"]},{"id":"am-nguyet-tinh","name":"Ám Nguyệt tinh","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu ở Liên minh tinh vực, quê cũ Tôn Thái muốn gửi tro cốt về.","detail":"Nằm trong Liên minh tinh vực. Là quê cũ Tôn Thái — nơi có Thiên Sơn, dưới chân núi có thôn trang. Tôn Thái nhờ Vương Lâm mang tro cốt về đây để lá rụng về cội.","nguon":["@c0625"]},{"id":"thien-son-am-nguyet-tinh","name":"Thiên Sơn (Ám Nguyệt tinh)","capDo":"khac","parentId":"am-nguyet-tinh","blurb":"Ngọn núi nơi dưới chân có thôn trang quê cũ Tôn Thái.","detail":"Trên Ám Nguyệt tinh có Thiên Sơn, dưới chân núi có thôn trang — quê cũ Tôn Thái muốn gửi tro cốt về.","nguon":["@c0625"]},{"id":"thanh-bao-hop-lau-nhiem-van","name":"Thành bảo hợp lâu (Nhiễm Vân tinh)","capDo":"khac","parentId":"nhiem-van-tinh","blurb":"Cơ sở nơi Tôn Thái làm người nắm tin tức cho Nhiễm gia.","detail":"Nơi Tôn Thái làm khách khanh nắm tin tức cho Nhiễm gia, cũng là nơi Vương Lâm gặp lại hắn.","nguon":["@c0625"]},{"id":"nhiem-van-tinh-627","name":"Nhiễm Vân tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc","blurb":"Tinh cầu của Nhiễm gia; nơi Vương Lâm ép ba người nộp tiên ngọc, mục tiêu Huyễn Đông được phái tới.","detail":"Nhiễm Vân tinh là tinh cầu của Nhiễm gia, nơi diễn ra việc Vương Lâm (Hứa mỗ) ép lão tổ Nhiễm gia, Tôn Tích và Tiêu Dao tán nhân nộp tiên ngọc cùng di vật người Huyễn gia. Đây cũng là nơi Liễu Mi phái Huyễn Đông tới xử lý người liên quan việc tộc nhân Huyễn gia mất tích.","theLucLienQuan":["Nhiễm gia (Nhiễm Vân tinh)","Huyễn gia"],"nguon":["@c0627"]},{"id":"thien-huyen-tinh-627","name":"Thiên Huyễn tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu phía nam, nơi có tổ trạch Huyễn gia.","detail":"Thiên Huyễn tinh là tinh cầu ở phía nam, nơi đặt tổ trạch Huyễn gia. Tại đây lão tổ Huyễn gia tra hỏi gia chủ Huyễn Phong Thần về việc tộc nhân mất tích bốn năm trước và ra lệnh nhổ tận gốc người liên quan.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0627"]},{"id":"van-ha-tinh","name":"Vân Hà tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc-q06","blurb":"Tinh cầu phát hiện mỏ quáng Kim Viêm (mỏ đá lửa kim loại).","detail":"Tinh cầu thuộc La Thiên tinh vực, nơi phát hiện một mỏ quáng Kim Viêm — mỏ đá lửa kim loại, thiên tài địa bảo người người tranh đoạt. Vương Lâm chưa biết vị trí cụ thể, định nhờ tinh đồ La Thiên tinh vực để tìm tới đoạt mỏ.","theLucLienQuan":[],"nguon":["@c0628"]},{"id":"mo-quang-kim-viem","name":"Mỏ quáng Kim Viêm","cn":"","capDo":"khac","parentId":"van-ha-tinh","blurb":"Mỏ đá lửa kim loại ở Vân Hà tinh, thiên tài địa bảo tranh đoạt.","detail":"Mỏ đá lửa kim loại tại Vân Hà tinh, thiên tài địa bảo mà người người tranh đoạt. Vương Lâm định lấy kim loại đá lửa từ mỏ để lấp đầy tính kim loại còn thiếu của hạt châu Thiên Nghịch; hắn nổi sát khí với kẻ tranh đoạt.","theLucLienQuan":[],"nguon":["@c0628"]},{"id":"van-ha-tinh-q06","name":"Vân Hà tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu bỏ đi không có tu sĩ, tràn ngập khói độc và chướng khí giết được tu sĩ; đích đến của Vương Lâm.","detail":"Một tinh cầu cách Nhiễm Vân tinh khá xa, dù đi không nghỉ cũng mất mấy tháng. Theo lời giới thiệu trên ngọc giản tinh đồ của Tôn Tích, Vân Hà tinh không có tu sĩ, là tinh cầu bỏ đi, tràn ngập khói độc và chướng khí có thể giết chết tu sĩ. Vương Lâm chọn nơi này làm đích đến sau mười ngày nghiên cứu tinh đồ.","theLucLienQuan":[],"nguon":["@c0629"]},{"id":"thien-huyen-chu-tinh","name":"Thiên Huyễn chủ tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Chủ tinh nơi đặt Huyễn gia; xuất xứ của tộc vệ Huyễn Đông.","detail":"Chủ tinh là nơi đặt đại thế lực Huyễn gia. Huyễn Đông tự xưng là nhị phẩm tộc vệ của Huyễn gia trên Thiên Huyễn chủ tinh, được phái xuống Nhiễm Vân tinh diệt người tham dự.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0629"]},{"id":"van-ha-tinh-tu-chan-hoang-phe","name":"Vân Hà tinh","capDo":"tinh-cau","parentId":null,"blurb":"Tu chân tinh cầu hoang phế màu xám thẫm phủ sương mù dày, có mỏ Kim Viêm và Vọng Nguyệt.","detail":"Tinh cầu tu chân hoang phế, màu xám thẫm phủ sương mù dày khiến thần thức không vào được và có tiếng rít gào cảnh cáo. Bên trong trời tối đen, mặt đất nứt nẻ mọc đầy xúc tu hư thối, tử khí đậm đặc do chính tinh cầu phát ra, các thành trì hoang tàn bị xúc tu bao vây. Nơi đây có mỏ Kim Viêm và mãnh thú Vọng Nguyệt; Vương Lâm nghi có xác Cổ Thần.","theLucLienQuan":[],"nguon":["@c0631"]},{"id":"loi-tien-gioi-da-huy","name":"Lôi tiên giới","capDo":"gioi-dien","parentId":null,"blurb":"Tiên giới đã bị hủy, nơi tổ tiên Huyễn gia từng là tiên nhân và để lại huyết mạch.","detail":"Một tiên giới đã bị hủy. Tổ tiên Huyễn gia vốn từng là tiên nhân của Lôi tiên giới; tiên giới bị hủy nhưng huyết mạch còn lưu lại, được Hoán huyết đại pháp luyện hóa truyền thừa.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0631"]},{"id":"tuyet-dia-ho-sau-hoang-tuyen-611","name":"Tuyệt địa hố sâu (vực hoàng tuyền)","capDo":"khac","parentId":null,"blurb":"Nơi Vương Lâm bị cầm chân mười bảy năm; khí âm hàn cực nồng, lực hút khủng khiếp kéo xuống, đáy là vực sâu vô tận như hoàng tuyền.","detail":"Một tuyệt địa hố sâu với khí âm hàn cực nồng đậm và lực hút khủng khiếp kéo mọi thứ xuống dưới. Trong hố có tảng đá lớn (nơi có Truyền Tống Trận) và khe núi không có lực hút (nơi điều tức). Đáy hố là vực sâu đen tối vô tận như hoàng tuyền, một thế giới bí ẩn nuốt mọi thứ. Vương Lâm dung nhập lực hút nơi này để lĩnh ngộ Đệ Tam Thức Hoàng Tuyền Chi Lực.","theLucLienQuan":[],"nguon":["@c0611"]},{"id":"tu-dai-tien-gioi-612","name":"Tứ đại tiên giới (Phong, Vũ, Lôi, Điện)","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Bốn mảnh tiên giới phân theo các thông đạo dẫn tới tiên vực viễn cổ, hình thành sau khi tiên vực bỏ rơi tu sĩ rời tinh không.","detail":"Tương truyền xưa có một tiên vực thần bí, về sau bỏ rơi tu sĩ rời khỏi tinh không, chỉ để lại các thông đạo phân thành Tứ đại tiên giới Phong, Vũ, Lôi, Điện — chỗ tu sĩ cao giai phi thăng. La Thiên tinh vực chính là Lôi tiên giới; Liên Minh Tinh Vực có Vũ tiên giới.","theLucLienQuan":[],"nguon":["@c0612"]},{"id":"la-thien-tinh-vuc-615","name":"La Thiên Tinh Vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực rộng lớn rực rỡ tinh quang, không có môn phái, chỉ có các tu chân gia tộc huyết thống.","detail":"Tinh vực rộng lớn chứa vô số tu chân tinh không kể xiết. Khác Liên Minh Tinh Vực, La Thiên Tinh Vực không có môn phái — chỉ người cùng huyết thống mới đủ lực ngưng tụ thành thế lực một phương, nên chỉ có các tu chân gia tộc. Đa số tu sĩ nơi đây biết tứ đại tiên giới phong-vũ-lôi-điện đều có tinh vực riêng.","theLucLienQuan":["Nhiễm gia"],"nguon":["@c0615"]},{"id":"la-van-tinh-vuc-615","name":"La Vân Tinh Vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực thuộc Lôi chi tiên giới, nơi Vương Lâm hiện ra sau khi qua trận lốc xoáy.","detail":"Tinh vực thuộc Lôi chi tiên giới trong tứ đại tiên giới phong-vũ-lôi-điện. Vương Lâm sau khi dung nhập trận lốc xoáy giống một truyền tống trận thì hiện ra tại đây, một tinh không hoàn toàn xa lạ với hắn, không phải Liên Minh Tinh Vực quê hương.","theLucLienQuan":[],"nguon":["@c0615"]},{"id":"nhiem-van-tinh-615","name":"Nhiễm Vân Tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc-615","blurb":"Tu chân tinh nơi Nhiễm gia cư trú trong La Thiên Tinh Vực.","detail":"Một tu chân tinh trong La Thiên Tinh Vực, là nơi cư trú của Nhiễm gia. Nhiễm Nguyệt cùng Nhiễm Thần, Nhiễm Phong và Tôn Tuyết Sơn từ đây đi thí luyện thì gặp nạn Minh vụ trùng.","theLucLienQuan":["Nhiễm gia"],"nguon":["@c0615"]},{"id":"hop-van-thanh-615","name":"Hợp vân thánh","cn":"","capDo":"khac","parentId":"la-thien-tinh-vuc-615","blurb":"Địa danh cách chỗ vây hãm khoảng bảy ngày đường về hướng bắc, gần nơi Hướng gia cư trú.","detail":"Địa danh ở La Thiên Tinh Vực mà Vương Lâm hỏi đường tìm tới, gắn với gia tộc Hướng gia theo lời nữ tử trong cuốn tranh. Tôn Tuyết Sơn cho biết cách chỗ bốn người bị vây bảy ngày đường về hướng bắc và xin dẫn đường tới.","theLucLienQuan":["Hướng gia"],"nguon":["@c0615"]},{"id":"khe-nut-ho-sau-yeu-linh-610","name":"Vùng đất Yêu Linh — khe nứt dưới hố sâu","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Khe rộng vài trượng dưới hố sâu vùng đất Yêu Linh, nơi Vương Lâm mắc kẹt ba năm.","detail":"Một cái khe rộng vài trượng nơi vùng đất Yêu Linh, là chỗ Vương Lâm ngồi tu ba năm. Bên ngoài khe là hố sâu có lực hút cực mạnh không theo quy tắc; lực hút từng bùng nổ lan vào nửa cái khe. Dưới đáy hố, trên một tảng đá lớn / bãi đá xiêu vẹo cách khe hai mươi trượng phía dưới đối diện cái khe có một Truyền Tống Trận cổ xưa thần bí.","theLucLienQuan":[],"nguon":["@c0610"]},{"id":"thuy-yeu-quan-c0613","name":"Thủy Yêu quận","cn":"","capDo":"khac","parentId":"yeu-linh-chi-dia","blurb":"Một trong chín quận Yêu Linh; nơi Vương Lâm dẫn đàn Văn thú tới để thu phục.","detail":"Thủy Yêu quận là quận Vương Lâm dẫn đàn Văn thú tới (thay vì Hỏa Yêu quận) mở túi trữ vật thu phục; nơi hơn hai phần ba Văn thú trưởng thành tự vẫn.","nguon":["@c0613"]},{"id":"hu-phu-thu-tu","name":"Hư phủ thứ tư","cn":"","capDo":"khac","parentId":null,"blurb":"Tòa hư phủ thứ tư mà bí mật vốn chỉ Huyết Tổ và Diêu Tích Huyết biết, đã bị Vương Lâm chiếm cứ.","detail":"Vương Lâm tiết lộ hư phủ không phải chỉ có ba tòa mà có tất cả bốn. Huyết Tổ thừa nhận hư phủ thứ tư tồn tại và đã bị Vương Lâm chiếm cứ; phải bắt Vương Lâm về mới vào được động phủ thật sự.","theLucLienQuan":[],"nguon":["@c0614"]},{"id":"la-thien-tinh-vuc-q06-c0616","name":"La Thiên Tinh Vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực Vương Lâm đang đến, chia bốn phía đông tây nam bắc, có nhiều Tu Chân Tinh.","detail":"Tinh vực rộng lớn chia làm bốn phía đông, tây, nam, bắc. Bắc vực có chủ tinh Nhiễm Vân Tinh và Thiên Huyễn Tinh cùng nhiều sao lệ thuộc. Đông Lâm Tinh (Đông Vực) còn gọi Đông Lâm S��t Tinh là ác mộng đè nặng dân nơi đây vì người đi ra từ đó đều tàn nhẫn.","theLucLienQuan":["Nhiễm Gia","Huyễn Gia","Tôn Gia"],"nguon":["@c0616"]},{"id":"thien-huyen-tinh-bac-vuc-c0616","name":"Thiên Huyễn Tinh","cn":"","capDo":"tinh-cau","parentId":"la-thien-tinh-vuc-q06-c0616","blurb":"Một trong năm đại chủ tinh, lệ thuộc bắc vực Nhiễm Vân Tinh; nơi đặt Huyễn gia và Hứa gia.","detail":"Một trong năm đại chủ tinh của La Thiên Tinh Vực, lệ thuộc bắc vực Nhiễm Vân Tinh, xung quanh còn nhiều sao lệ thuộc. Là nơi cư ngụ của Huyễn gia (đại trưởng lão Mi nhi) và Hứa gia danh giá quyền thế.","theLucLienQuan":["Huyễn Gia","Hứa gia"],"nguon":["@c0616"]},{"id":"dong-lam-sat-tinh-c0616","name":"Đông Lâm Tinh","cn":"","aliases":["Đông Lâm Sát Tinh"],"capDo":"tinh-cau","parentId":"la-thien-tinh-vuc-q06-c0616","blurb":"La Thiên Đông Vực, còn gọi Đông Lâm Sát Tinh, nơi quỷ dị hư vô mờ mịt lúc hiện lúc ẩn.","detail":"Chính là La Thiên Đông Vực, còn có tên Đông Lâm Sát Tinh. Nơi quỷ dị hư vô mờ mịt lúc hiện lúc ẩn; người đi ra từ đó đều tàn nhẫn (từng có tu sĩ giết cả một gia tộc), là ác mộng đè nặng dân La Thiên Tinh Vực.","theLucLienQuan":[],"nguon":["@c0616"]},{"id":"dong-xoay-day-ho-yeu-linh","name":"Dòng xoáy / cái khe (đáy hố sâu vùng yêu linh)","cn":"","capDo":"khac","parentId":"vung-dat-yeu-linh","blurb":"Nơi tận đáy hố trong vùng đất yêu linh, có dòng xoáy cực lớn phát ra lực hút khủng khiếp; là thông đạo nhìn ra La Thiên tinh vực.","detail":"Tận đáy hố sâu vùng đất yêu linh có một hành lang ngắn dẫn tới dòng xoáy cực lớn — nguồn của lực hút khủng khiếp khiến huyết nhục lưu chuyển dữ dội. Qua dòng xoáy nhìn thấy La Thiên tinh vực; nơi đây có truyền tống trận cổ chỉ khởi động được bằng La Yêu thạch. Vương Lâm ném bức tranh cắm vào vách đá trong một cái khe rồi vỗ sụp chôn sâu.","theLucLienQuan":[],"nguon":["@c0612"]},{"id":"vu-tien-gioi-lien-minh-tinh-vuc","name":"Vũ tiên giới (Liên Minh Tinh Vực)","cn":"","capDo":"gioi-dien","parentId":null,"blurb":"Một trong Tứ đại tiên giới thuộc Liên Minh Tinh Vực, nơi Thiên Nghịch châu từng xuất hiện.","detail":"Vũ tiên giới là một trong Tứ đại tiên giới (Phong, Vũ, Lôi, Điện), thuộc Liên Minh Tinh Vực. Đây là nơi Thiên Nghịch châu lại xuất hiện sau khi quỷ dị biến mất khỏi La Thiên tinh vực.","theLucLienQuan":[],"nguon":["@c0612"]},{"id":"chu-tuoc-tinh","name":"Chu Tước tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu nơi Vương Lâm lưu lại túi trữ vật vô tình, chờ ngày được mở ra.","detail":"Chu Tước tinh là nơi Vương Lâm để lại một túi trữ vật vô tình chờ ngày được mở ra — gắn với nội tâm và quá khứ chưa hé lộ hết của hắn.","theLucLienQuan":[],"nguon":["@c0612"]},{"id":"thanh-bac-nhiem-van-tinh-q06","name":"Thành Bắc (tòa thành Vương Lâm trú)","cn":"","capDo":"thanh","parentId":"nhiem-van-tinh","blurb":"Tòa thành nơi Vương Lâm trú trên Nhiễm Vân Tinh, linh khí đậm đặc hơn ngoại thành, do Tôn Gia quản.","detail":"Chỗ ở của Vương Lâm nơi thành Bắc trên Nhiễm Vân Tinh; linh khí nơi đây đậm đặc hơn ngoại thành, do Tôn Gia kiểm soát và Tôn Khải Minh phụ trách. Gần chỗ trú có một ngọn núi nơi người thanh niên nữ giả nam tĩnh tọa thổ nạp.","theLucLienQuan":["Tôn Gia"],"nguon":["@c0621"]},{"id":"tu-thanh-tinh-625","name":"Tứ Thánh tinh","cn":"","capDo":"tinh-cau","parentId":null,"blurb":"Tinh cầu nơi Chu Tước tử đời thứ nhất tách Chu Tước tinh ra; bản thân là một chi nhánh của Tứ Thánh tông.","detail":"Tứ Thánh tinh là nơi nghe đồn Chu Tước tử đời thứ nhất bắt đầu tách Chu Tước tinh ra. Bản thân Tứ Thánh tinh cũng chỉ là một chi nhánh của Tứ Thánh tông — tông phái lớn ngang hàng Thi Âm Tông. Theo mạch suy ấy, Vương Lâm với xuất thân Chu Tước tinh có thể tính là đệ tử bên ngoài của Tứ Thánh tông.","theLucLienQuan":["Tứ Thánh tông","Chu Tước Tinh"],"nguon":["@c0625"]},{"id":"lien-minh-tinh-vuc-625","name":"Liên minh tinh vực","cn":"","capDo":"vuc","parentId":null,"blurb":"Tinh vực chứa Chu Tước tinh, Ám Nguyệt tinh; phạm vi hoạt động của Thi Âm Tông và Tứ Thánh tông.","detail":"Liên minh tinh vực là khu vực rộng lớn chứa các tinh cầu như Chu Tước tinh và Ám Nguyệt tinh. Đây là phạm vi hoạt động của hai tông phái lớn nhất là Thi Âm Tông và Tứ Thánh tông, với ảnh hưởng vươn tới Tu chân Liên minh.","theLucLienQuan":["Thi Âm Tông","Tứ Thánh tông"],"nguon":["@c0625"]},{"id":"ton-gia-thanh-nhiem-van-tinh-629","name":"Tôn gia thành","cn":"","capDo":"thanh","parentId":"nhiem-van-tinh-627","blurb":"Tòa thành thuộc Tôn gia trên Nhiễm Vân tinh, nơi có người trẻ tuổi tu sĩ bị tiếng quát Huyễn Đông chấn thương.","detail":"Thành trì của Tôn gia trên Nhiễm Vân tinh. Dưới một núi đá ở thành có tu sĩ tu vi thấp đang thổ nạp, bị thanh âm như sấm của Huyễn Đông chấn động tâm mạch phun máu.","theLucLienQuan":["Tôn gia"],"nguon":["@c0629"]},{"id":"lo-chi-tien-gioi-633","name":"Lôi chi tiên giới","capDo":"gioi-dien","parentId":null,"blurb":"Tiên giới nơi một lão tổ bước hai của Huyễn gia chết trong cuộc tranh đoạt năm xưa.","detail":"Theo lời Tôn Tích, Huyễn gia từng có hai lão tổ tu vi bước hai (tu đạo); một trong số đó đã chết tại Lôi chi tiên giới trong cuộc tranh đoạt năm xưa, chỉ còn lại một lão tổ đủ uy lực quét ngang chúng sinh.","theLucLienQuan":["Huyễn gia"],"nguon":["@c0633"]}]};
